INSERT INTO public.workflow_entity (name, active, nodes, connections, "createdAt", "updatedAt", settings, "staticData", "pinData", "versionId", "triggerCount", id, meta, "parentFolderId", "isArchived", "versionCounter", description, "activeVersionId") VALUES ('Instagram Reels Automation', false, '[{"parameters":{"rule":{"interval":[{"triggerAtHour":9},{"triggerAtHour":18,"triggerAtMinute":10}]}},"type":"n8n-nodes-base.scheduleTrigger","typeVersion":1.2,"position":[0,0],"id":"65479740-052e-4111-9f59-dc79dad9defc","name":"Schedule Trigger"},{"parameters":{"documentId":{"__rl":true,"value":"1I9Q9PmianRTL7kN7WNXT5FSdXADwFWOgrLWF3VWMxNY","mode":"list","cachedResultName":"Reels Automation","cachedResultUrl":"https://docs.google.com/spreadsheets/d/1I9Q9PmianRTL7kN7WNXT5FSdXADwFWOgrLWF3VWMxNY/edit?usp=drivesdk"},"sheetName":{"__rl":true,"value":"gid=0","mode":"list","cachedResultName":"Sheet1","cachedResultUrl":"https://docs.google.com/spreadsheets/d/1I9Q9PmianRTL7kN7WNXT5FSdXADwFWOgrLWF3VWMxNY/edit#gid=0"},"filtersUI":{"values":[{"lookupColumn":"Status"}]},"options":{"returnFirstMatch":true}},"type":"n8n-nodes-base.googleSheets","typeVersion":4.7,"position":[224,0],"id":"bc91fe88-671a-4c40-84ba-1831ac44fc7c","name":"Get row(s) in sheet","credentials":{"googleSheetsOAuth2Api":{"id":"WaT00KohKl28XfVA","name":"Google Sheets account"}}},{"parameters":{"promptType":"define","text":"=Video Topic: {{ $json.Outline }}","options":{"systemMessage":"=You are a social media expert who writes engaging and SEO optimized instagram captions.\ncreate a short and catchy caption for the given video topic.\nMake sure the tone sounds natural and appealing to the audience.\nAdd two highly relevant hashtags at the end that fit the topic."}},"type":"@n8n/n8n-nodes-langchain.agent","typeVersion":2.2,"position":[448,0],"id":"5c8b3930-ca9b-410d-a90e-a8f3033c44b4","name":"AI Agent"},{"parameters":{"options":{}},"type":"@n8n/n8n-nodes-langchain.lmChatGoogleGemini","typeVersion":1,"position":[416,240],"id":"beb0a009-a523-4f10-ad6b-7ef1b3191f24","name":"Google Gemini Chat Model","credentials":{"googlePalmApi":{"id":"Z6IRL3w4ntx5FaCK","name":"Google Gemini(PaLM) Api account"}}},{"parameters":{"httpRequestMethod":"POST","graphApiVersion":"v23.0","node":"17841466876322","edge":"media","options":{"queryParameters":{"parameter":[{"name":"video_url","value":"=https://res.cloudinary.com/drzrtfh87/video/upload/Reels/{{ $(''Get row(s) in sheet'').item.json[''File name''] }}"},{"name":"caption","value":"={{ $json.output }}"},{"name":"media_type","value":"REELS"}]}}},"type":"n8n-nodes-base.facebookGraphApi","typeVersion":1,"position":[800,0],"id":"7ee7aabf-4443-4c33-aebb-5cab506d09a3","name":"Facebook Graph API","credentials":{"facebookGraphApi":{"id":"RqTwC0uROcgMfOXq","name":"Facebook Graph account"}}},{"parameters":{"httpRequestMethod":"POST","graphApiVersion":"v23.0","node":"17841466876322","edge":"media_publish","options":{"queryParameters":{"parameter":[{"name":"creation_id","value":"={{ $json.id }}"}]}}},"type":"n8n-nodes-base.facebookGraphApi","typeVersion":1,"position":[1248,0],"id":"5ed0be72-5269-428e-8c54-a763b96bf670","name":"Facebook Graph API1","retryOnFail":true,"waitBetweenTries":5000,"credentials":{"facebookGraphApi":{"id":"RqTwC0uROcgMfOXq","name":"Facebook Graph account"}}},{"parameters":{"amount":60},"type":"n8n-nodes-base.wait","typeVersion":1.1,"position":[1024,0],"id":"595bb116-b8bb-45de-9046-b3943a60022f","name":"Wait","webhookId":"93000f33-7d73-45db-a1fb-3089574b98fc"},{"parameters":{"operation":"update","documentId":{"__rl":true,"value":"1I9Q9PmianRTL7kN7WNXT5FSdXADwFWOgrLWF3VWMxNY","mode":"list","cachedResultName":"Reels Automation","cachedResultUrl":"https://docs.google.com/spreadsheets/d/1I9Q9PmianRTL7kN7WNXT5FSdXADwFWOgrLWF3VWMxNY/edit?usp=drivesdk"},"sheetName":{"__rl":true,"value":"gid=0","mode":"list","cachedResultName":"Sheet1","cachedResultUrl":"https://docs.google.com/spreadsheets/d/1I9Q9PmianRTL7kN7WNXT5FSdXADwFWOgrLWF3VWMxNY/edit#gid=0"},"columns":{"mappingMode":"defineBelow","value":{"row_number":"={{ $(''Get row(s) in sheet'').item.json.row_number }}","Status":"Posted"},"matchingColumns":["row_number"],"schema":[{"id":"File name","displayName":"File name","required":false,"defaultMatch":false,"display":true,"type":"string","canBeUsedToMatch":true,"removed":true},{"id":"Outline","displayName":"Outline","required":false,"defaultMatch":false,"display":true,"type":"string","canBeUsedToMatch":true,"removed":true},{"id":"Status","displayName":"Status","required":false,"defaultMatch":false,"display":true,"type":"string","canBeUsedToMatch":true,"removed":false},{"id":"row_number","displayName":"row_number","required":false,"defaultMatch":false,"display":true,"type":"number","canBeUsedToMatch":true,"readOnly":true,"removed":false}],"attemptToConvertTypes":false,"convertFieldsToString":false},"options":{}},"type":"n8n-nodes-base.googleSheets","typeVersion":4.7,"position":[1472,0],"id":"c6058039-2ab7-412f-ba75-2e93892ca8e8","name":"Update row in sheet","credentials":{"googleSheetsOAuth2Api":{"id":"WaT00KohKl28XfVA","name":"Google Sheets account"}}}]', '{"Schedule Trigger":{"main":[[{"node":"Get row(s) in sheet","type":"main","index":0}]]},"Get row(s) in sheet":{"main":[[{"node":"AI Agent","type":"main","index":0}]]},"Google Gemini Chat Model":{"ai_languageModel":[[{"node":"AI Agent","type":"ai_languageModel","index":0}]]},"AI Agent":{"main":[[{"node":"Facebook Graph API","type":"main","index":0}]]},"Facebook Graph API":{"main":[[{"node":"Wait","type":"main","index":0}]]},"Wait":{"main":[[{"node":"Facebook Graph API1","type":"main","index":0}]]},"Facebook Graph API1":{"main":[[{"node":"Update row in sheet","type":"main","index":0}]]}}', '2026-02-17 10:22:46.405+00', '2026-02-23 13:23:24.731+00', '{"executionOrder":"v1","availableInMCP":false}', NULL, '{}', '7442535b-a787-41b6-8dee-c2dee27b7889', 0, '8yy_dz5ufAqwojoIkQI9J', '{"templateCredsSetupCompleted":true}', 'CElZg6UerPvaDkWE', false, 3, NULL, NULL);
INSERT INTO public.workflow_entity (name, active, nodes, connections, "createdAt", "updatedAt", settings, "staticData", "pinData", "versionId", "triggerCount", id, meta, "parentFolderId", "isArchived", "versionCounter", description, "activeVersionId") VALUES ('Detalles Linea de pedido', false, '[{"parameters":{"options":{"systemMessage":"=Eres un asistente empresarial conectado al sistema Odoo 18 de JumpJibe.\n\nTu función es ayudar al usuario a consultar y comprender los **detalles de pedidos de venta** usando el siguiente endpoint:\n\n➡️ https://jumpjibe.com/api/sale_order_linea_details/<string:order_number>\n\nEjemplo de uso:\nhttps://jumpjibe.com/api/sale_order_linea_details/SO0231\n\nEste endpoint devuelve los detalles de un pedido específico, incluyendo:\n- Número de pedido\n- Fecha del pedido y fecha efectiva\n- Cliente asociado\n- Dirección de envío (calle, ciudad, estado, país)\n- Productos vendidos, cantidad, precio unitario y subtotal\n\nLa respuesta JSON del endpoint tiene este formato:\n{\n  \"pedido\": \"SO0231\",\n  \"total_productos\": 3,\n  \"detalles\": [\n    {\n      \"order_number\": \"SO0231\",\n      \"order_date\": \"2025-10-13\",\n      \"effective_date\": \"2025-10-14\",\n      \"customer_name\": \"Distribuidora Las Lomas C.A.\",\n      \"shipping_address\": \"Av. Principal, Caracas, Distrito Capital, Venezuela\",\n      \"product_name\": \"Café Premium 500g\",\n      \"quantity\": 10,\n      \"unit_price\": 12.5,\n      \"subtotal\": 125.0\n    }\n  ]\n}\n\n🧭 Tu objetivo:\n- Interpretar preguntas naturales de los usuarios relacionadas con pedidos de venta.\n- Generar la URL correcta con el número de pedido.\n- Presentar la información en un formato claro, profesional y comprensible.\n- Agregar valor explicando el contexto comercial de los datos.\n\n---\n\n### 🔍 Instrucciones de comportamiento\n\n1️⃣ Si el usuario pregunta por un pedido específico (por ejemplo, “Muéstrame el pedido SO0452”), consulta el endpoint:\n   ➡️ https://jumpjibe.com/api/sale_order_linea_details/SO0452\n\n2️⃣ Si no proporciona número de pedido, pídeselo educadamente.\n\n3️⃣ Cuando recibas los datos, tradúcelos a un formato interpretativo, por ejemplo:\n\n💬 Ejemplo de respuesta para el cliente:\n> El pedido **SO0452**, realizado el **13/10/2025**, pertenece al cliente **Distribuidora Las Lomas C.A.**  \n> Se envía a **Av. Principal, Caracas, Venezuela**.  \n> Incluye **3 productos**:\n> - 10x Café Premium 500g — $12.50 c/u → subtotal $125.00  \n> - 5x Azúcar Morena 1kg — $8.00 c/u → subtotal $40.00  \n> - 2x Cacao Natural 250g — $15.00 c/u → subtotal $30.00  \n> **Total estimado:** $195.00\n\n4️⃣ Si no se encuentran resultados:\n> “No se encontraron datos para el pedido solicitado. Por favor verifica el número de pedido.”\n\n5️⃣ Si ocurre un error técnico:\n> “Hubo un inconveniente al procesar tu solicitud. Inténtalo nuevamente más tarde o revisa el número del pedido.”\n\n---\n\n### 💡 Ejemplos de interacción\n\n🧍 Usuario:\n> ¿Qué productos tiene el pedido SO0231?\n\n🤖 IA:\n> Consultando detalles del pedido **SO0231**...\n> El pedido fue realizado el **13/10/2025** por **Café del Sol C.A.**  \n> Incluye los siguientes productos:\n> - 6x Café Gourmet 250g — $10.00 c/u → $60.00  \n> - 2x Azúcar Morena — $7.00 c/u → $14.00  \n> En total, **8 productos por $74.00**.\n\n---\n\n🧍 Usuario:\n> Enséñame la dirección de entrega del pedido SO0450.\n\n🤖 IA:\n> El pedido **SO0450** se entregará en **Calle 10 con Av. 5, Maracaibo, Venezuela**.  \n> Cliente: **Alimentos Andinos S.A.**\n\n---\n\n### 🎯 Objetivo del asistente\n\nTu meta es ofrecer **respuestas útiles, humanas y orientadas al negocio**.  \nNo devuelvas datos sin contexto: **interpreta los números** (por ejemplo, indica si el pedido es grande, si tiene muchos productos o si parece urgente).\n\nHabla con tono profesional y empático, como un **asesor comercial digital de JumpJibe**.\n\n"}},"type":"@n8n/n8n-nodes-langchain.agent","typeVersion":2.2,"position":[240,0],"id":"1888e29c-822f-44c1-8079-0bb158029dd3","name":"AI Agent"},{"parameters":{"options":{}},"type":"@n8n/n8n-nodes-langchain.lmChatGoogleGemini","typeVersion":1,"position":[128,208],"id":"19bdc6d1-9c32-4f10-ba77-705a82dae0f2","name":"Google Gemini Chat Model"},{"parameters":{"contextWindowLength":30},"type":"@n8n/n8n-nodes-langchain.memoryBufferWindow","typeVersion":1.3,"position":[272,208],"id":"635985f5-36a6-4552-97b2-56e7e2b90c24","name":"Simple Memory"},{"parameters":{"toolDescription":"=Esta herramienta permite obtener la informacion de la orden por order_number","url":"={{ /*n8n-auto-generated-fromAI-override*/ $fromAI(''URL'', ``, ''string'') }}","options":{}},"type":"n8n-nodes-base.httpRequestTool","typeVersion":4.2,"position":[656,96],"id":"b8114628-c45c-4196-b9fe-71eca6f77bf1","name":"get_order_information"},{"parameters":{"sendTo":"={{ /*n8n-auto-generated-fromAI-override*/ $fromAI(''To'', ``, ''string'') }}","subject":"={{ /*n8n-auto-generated-fromAI-override*/ $fromAI(''Subject'', ``, ''string'') }}","message":"={{ /*n8n-auto-generated-fromAI-override*/ $fromAI(''Message'', ``, ''string'') }}","options":{}},"type":"n8n-nodes-base.gmailTool","typeVersion":2.1,"position":[416,208],"id":"b96188d4-8e10-41ff-83cf-00601e0c480f","name":"send_email","webhookId":"3972b7b9-cc09-41b1-b28b-4c223e11a07b"},{"parameters":{"public":true,"mode":"webhook","options":{}},"type":"@n8n/n8n-nodes-langchain.chatTrigger","typeVersion":1.3,"position":[0,0],"id":"e4dc511d-3120-473b-a163-6b072d704d35","name":"When chat message received","webhookId":"b9d1fd06-1b3a-448a-ab7a-579d326b60f9","alwaysOutputData":false}]', '{"Google Gemini Chat Model":{"ai_languageModel":[[{"node":"AI Agent","type":"ai_languageModel","index":0}]]},"Simple Memory":{"ai_memory":[[{"node":"AI Agent","type":"ai_memory","index":0}]]},"get_order_information":{"ai_tool":[[{"node":"AI Agent","type":"ai_tool","index":0}]]},"send_email":{"ai_tool":[[{"node":"AI Agent","type":"ai_tool","index":0}]]},"When chat message received":{"main":[[{"node":"AI Agent","type":"main","index":0}]]}}', '2025-12-18 18:47:08.433+00', '2025-12-18 18:47:08.433+00', '{"executionOrder":"v1"}', NULL, '{}', 'f5909128-0cb3-45eb-80fb-3b8d6f4d82a7', 0, '8B4CzVgeUkM9PChM', NULL, 'YA7KJx2bNJlfW9mi', false, 1, NULL, NULL);
INSERT INTO public.workflow_entity (name, active, nodes, connections, "createdAt", "updatedAt", settings, "staticData", "pinData", "versionId", "triggerCount", id, meta, "parentFolderId", "isArchived", "versionCounter", description, "activeVersionId") VALUES ('Postiz', false, '[{"parameters":{},"type":"n8n-nodes-base.manualTrigger","typeVersion":1,"position":[0,0],"id":"3ccf4c8d-bf62-4004-bc71-98120b555ad6","name":"When clicking ‘Execute workflow’"},{"parameters":{"posts":{"post":[{},{}]}},"type":"n8n-nodes-postiz.postiz","typeVersion":1,"position":[208,0],"id":"99c06261-64bc-44d1-a7af-c9ed87d8a0fe","name":"Postiz"},{"parameters":{"operation":"generateVideo","customParameters":{"parameter":[{}]}},"type":"n8n-nodes-postiz.postiz","typeVersion":1,"position":[416,0],"id":"ed90b811-7bb4-47dc-aea7-b81f3ad5fd32","name":"Postiz1"}]', '{"When clicking ‘Execute workflow’":{"main":[[{"node":"Postiz","type":"main","index":0}]]},"Postiz":{"main":[[{"node":"Postiz1","type":"main","index":0}]]}}', '2026-02-28 13:25:12.717+00', '2026-02-28 13:25:12.717+00', '{"executionOrder":"v1","availableInMCP":false}', NULL, '{}', '7572b751-117f-4549-8750-6f126cfb1a90', 0, 'A0g-5JcQljxLqo7fMefMm', NULL, 'CElZg6UerPvaDkWE', false, 2, NULL, NULL);
INSERT INTO public.workflow_entity (name, active, nodes, connections, "createdAt", "updatedAt", settings, "staticData", "pinData", "versionId", "triggerCount", id, meta, "parentFolderId", "isArchived", "versionCounter", description, "activeVersionId") VALUES ('simple-n8n-instagram', false, '[{"parameters":{"pollTimes":{"item":[{"mode":"everyMinute"}]},"triggerOn":"specificFolder","folderToWatch":{"__rl":true,"value":"1sSVK7IDYQkV_kf1ZTpCSscOLPIM7Ggbt","mode":"list","cachedResultName":"integraia-instagram","cachedResultUrl":"https://drive.google.com/drive/folders/1sSVK7IDYQkV_kf1ZTpCSscOLPIM7Ggbt"},"event":"fileCreated","options":{}},"type":"n8n-nodes-base.googleDriveTrigger","typeVersion":1,"position":[-656,0],"id":"360f7477-f023-47f9-b0d3-1cbcab23f9cc","name":"Google Drive Trigger","credentials":{"googleDriveOAuth2Api":{"id":"HT68wKiMexoagMym","name":"Google Drive oracle-fedora"}}},{"parameters":{"operation":"download","fileId":{"__rl":true,"value":"={{ $json.id }}","mode":"id"},"options":{}},"type":"n8n-nodes-base.googleDrive","typeVersion":3,"position":[-448,0],"id":"e43c3eb1-a3d0-4dea-b78f-cb3ae6319309","name":"Download file","credentials":{"googleDriveOAuth2Api":{"id":"HT68wKiMexoagMym","name":"Google Drive oracle-fedora"}}},{"parameters":{"resource":"image","operation":"analyze","modelId":{"__rl":true,"value":"gpt-4o-mini","mode":"list","cachedResultName":"GPT-4O-MINI"},"text":"Rol: Eres un Director de Marketing Digital y Automatización (Growth Hacker) con amplia experiencia en embudos de venta orgánicos, community management y automatización de procesos con n8n. Tu especialidad es convertir cualquier activo visual en una campaña multicanal (Instagram, Facebook, WhatsApp) que genere conversiones (instalaciones de producto) sin depender de pauta publicitaria.\n\nObjetivo Principal: Al recibir una imagen, debes analizarla para extraer información valiosa y, en base a tu conocimiento del comportamiento del consumidor y las capacidades de automatización, generar un plan de contenido persuasivo y accionable que convenza a la audiencia de instalar el producto destacado, enfatizando sus bondades y la ventaja de no requerir licencias costosas (o ser una solución gratuita/de código abierto).\n\nContexto del Producto: Asume que la imagen está relacionada directa o indirectamente con un producto o servicio (puede ser una herramienta digital, un bien físico, un servicio comunitario). Tu misión es posicionarlo como la mejor opción, resaltando su calidad, facilidad de uso y el hecho de que no implica pagar licencias (es gratuito, freemium, open source, o de pago único sin suscripciones recurrentes).\n\nInstrucciones Específicas a seguir para CADA imagen:\n\nAnálisis Estratégico de la Imagen (Extracción de Insights):\n\nIdentifica el elemento persuasivo clave: ¿Qué parte de la imagen puede usarse como \"gancho\" para mostrar el valor del producto? (Ej: una interfaz limpia, un resultado visible, un grupo de personas felices usando algo, un antes/después).\n\nDetecta el \"punto de dolor\" o \"deseo\": ¿Qué problema resuelve o qué deseo satisface el contexto de la imagen? (Ej: una imagen de una persona estresada organizando papeles vs. una persona relajada con una tablet).\n\nExtrae elementos para automatización (n8n): ¿Qué flujos podrían conectarse con esta imagen? (Ej: si es un lead magnet, podrías sugerir un flujo de n8n que envíe un WhatsApp automático al usuario que comente \"INFO\").\n\nAnaliza el sentimiento y la identidad visual: Colores, tipografías, emociones. Esto definirá el tono de la comunicación en cada canal.\n\nGeneración de Contenido Persuasivo Multicanal (Basado en tu análisis):\nGenera un paquete completo de contenido listo para publicar y automatizar, orientado a la conversión (instalación).\n\nPara Instagram (Feed, Reels, Historias):\n\nCopy Persuasivo: Redacta un caption que use el modelo AIDA (Atención, Interés, Deseo, Acción). Debe incluir:\n\nHook potente (primeras 2 líneas) que hable del beneficio sin pagar licencias.\n\nStorytelling que conecte la imagen con el problema que resuelve el producto.\n\nLlamado a la acción (CTA) claro: \"Link en bio para instalarlo gratis\", \"Comenta ''INSTALAR'' y te enviaré el paso a paso por DM (automatizado con n8n)\".\n\nHashtags de conversión: Mezcla de hashtags de nicho + hashtags relacionados con \"gratis\", \"opensource\", \"ahorro\", \"tecnologíaaccesible\".\n\nIdea para Reel/Historia: Sugiere un micro-video que muestre un \"tip rápido\" del producto, con una overlay de texto que diga \"Sin pagar licencias nunca\". O una encuesta en historias: \"¿Sigues pagando por [software X]? Nosotros no 😉\".\n\nPara Facebook (Público más amplio y grupos):\n\nTexto para el post: Adapta el copy de Instagram para un tono más conversacional y de comunidad. Enfócate en el valor para grupos o pequeñas empresas.\n\nTexto para grupos de Facebook: Crea una versión más personal y de ayuda, como si compartieras un \"tip de experto\" en un grupo de emprendedores. Ej: \"Les comparto esta herramienta que uso para [beneficio] y lo mejor: cero licencias. La imagen muestra cómo...\"\n\nPara WhatsApp (Mensajería directa y listas de difusión):\n\nMensaje de bienvenida automatizado (vía n8n): Redacta un mensaje cálido y directo para cuando alguien pida información. Ej: \"¡Hola! Gracias por tu interés. Tal como viste en la imagen, con [Producto] puedes lograr [beneficio] sin pagar licencias. Aquí tienes el link de instalación directa: [link]. ¿Te gustaría una demo rápida?\".\n\nContenido para estado de WhatsApp: Una frase corta + la imagen, con un CTA que dirija a una lista de difusión automatizada.\n\nIdeas de Automatización con n8n (El \"arma secreta\"):\nPropón flujos concretos que el usuario (tu cliente) podría implementar en n8n para escalar este proceso sin esfuerzo manual.\n\nEjemplo 1: \"Si alguien comenta ''INSTALAR'' en Instagram, n8n puede capturar su usuario y enviarle automáticamente un mensaje directo con el enlace de descarga y un videotutorial.\"\n\nEjemplo 2: \"Puedes crear un flujo en n8n que, cada vez que publiques una imagen como esta, genere automáticamente un post en Facebook y un mensaje para una lista de difusión de WhatsApp, ahorrándote tiempo.\"\n\nEjemplo 3: \"Si la imagen es de un evento o promoción, n8n puede crear un lead en tu CRM cada vez que alguien haga clic en el link de la bio.\"\n\nFormato de Salida (IMPORTANTE):\nPresenta la información de manera profesional y accionable. Usa este esquema:\n\nANÁLISIS DE LA IMAGEN Y OPORTUNIDAD DE CONVERSIÓN\n\nElemento persuasivo clave: [Ej: La interfaz limpia del dashboard]\n\nPunto de dolor que ataca: [Ej: La complejidad de otras herramientas caras]\n\nPúblico objetivo principal: [Ej: Emprendedores digitales, pequeñas empresas]\n\nCONTENIDO PARA INSTAGRAM\n\nCopy Persuasivo (Modelo AIDA):\n\n[Escribe aquí el caption completo con un hook sobre el ahorro y un CTA claro. Incluye emojis estratégicos.]\n\nHashtags de Conversión:\n\n[Lista de 15 hashtags mezclando nicho + términos como #SinLicencias #TecnologíaGratis #AhorroDigital]\n\nIdea de Reel/Historia:\n\n[Sugerencia de video corto o interacción para stories]\n\nCONTENIDO PARA FACEBOOK\n\nPost en muro/página:\n\n[Texto adaptado para Facebook]\n\nPost para grupos:\n\n[Versión más de ayuda y menos comercial]\n\nCONTENIDO PARA WHATSAPP (AUTOMATIZABLE CON n8n)\n\nMensaje automático de bienvenida:\n\n[Mensaje que enviaría el bot de n8n al recibir una solicitud]\n\nTexto para Estado de WhatsApp:\n\n[Frase corta + llamada a la acción]\n\nIDEAS DE AUTOMATIZACIÓN CON n8n (Para escalar)\n\nFlujo 1: [Descripción del flujo y qué problema resuelve, ej: \"Auto-DM en Instagram con link de descarga\"]\n\nFlujo 2: [Descripción, ej: \"Publicación cruzada automática a Facebook y creación de lead en CRM\"]\n\nRegla de Oro: Tu objetivo final no es solo crear contenido bonito, sino generar instalaciones y conversiones. Cada sugerencia debe estar impregnada de psicología persuasiva y un conocimiento profundo de cómo las automatizaciones (n8n) pueden multiplicar el resultado sin necesidad de inversión en publicidad.","inputType":"base64","options":{}},"type":"@n8n/n8n-nodes-langchain.openAi","typeVersion":2.1,"position":[-240,0],"id":"447cf81e-99c1-4d63-8eac-730dfeecd897","name":"Analyze image","credentials":{"openAiApi":{"id":"SynY9HmZH2SsZkWD","name":"OpenAi account"}}},{"parameters":{"operation":"create","base":{"__rl":true,"value":"appaKyLh9iWKk9nbv","mode":"list","cachedResultName":"IG Image Post","cachedResultUrl":"https://airtable.com/appaKyLh9iWKk9nbv"},"table":{"__rl":true,"value":"tblsZRdrRHJRNT2Oq","mode":"list","cachedResultName":"Passthrough","cachedResultUrl":"https://airtable.com/appaKyLh9iWKk9nbv/tblsZRdrRHJRNT2Oq"},"columns":{"mappingMode":"defineBelow","value":{"Caption":"={{ $json[''0''].content[0].text }}","Name":"={{ $(''Google Drive Trigger'').item.json.name }}","URL":"={{ $(''Download file'').item.json.webContentLink }}"},"matchingColumns":[],"schema":[{"id":"Name","displayName":"Name","required":false,"defaultMatch":false,"canBeUsedToMatch":true,"display":true,"type":"string","readOnly":false,"removed":false},{"id":"Caption","displayName":"Caption","required":false,"defaultMatch":false,"canBeUsedToMatch":true,"display":true,"type":"string","readOnly":false,"removed":false},{"id":"URL","displayName":"URL","required":false,"defaultMatch":false,"canBeUsedToMatch":true,"display":true,"type":"string","readOnly":false,"removed":false}],"attemptToConvertTypes":false,"convertFieldsToString":false},"options":{}},"type":"n8n-nodes-base.airtable","typeVersion":2.1,"position":[-32,0],"id":"6ec590b0-1107-4926-b3c4-e711186d5107","name":"Create a record","credentials":{"airtableTokenApi":{"id":"Y1Wv5aYPrI2aRl3m","name":"Airtable Personal Access Token account"}}},{"parameters":{"httpRequestMethod":"POST","graphApiVersion":"v23.0","node":"17841448062796459","edge":"media","options":{"queryParameters":{"parameter":[{"name":"image_url","value":"={{ $json.fields.URL }}"},{"name":"cap