ext.map(item => Array.isArray(item) ? item.join(''\\n'') : item).join('','') }}","type":"string"},{"id":"0ce2eaa6-9b19-45cf-823e-f2aab0c8af45","name":"session_id","value":"={{ $(''Texto_o_Audio?'').item.json.session_id }}","type":"string"},{"id":"100f120e-da0f-42b0-ad99-0300e8d82216","name":"account_id","value":"={{ $(''Texto_o_Audio?'').item.json.account_id }}","type":"string"},{"id":"bc8acf8d-31f1-461c-bbab-e45e4169c9b4","name":"conversation_id","value":"={{ $(''Texto_o_Audio?'').item.json.conversation_id }}","type":"string"},{"id":"bd48bd51-341d-4292-adef-fc7c0316b54f","name":"message_type","value":"={{ $(''Texto_o_Audio?'').item.json.message_type }}","type":"string"},{"id":"eae6bd01-42f3-409b-88c3-f100d02d8884","name":"user_name","value":"={{ $(''Texto_o_Audio?'').item.json.user_name }}","type":"string"},{"id":"0ef35dab-5685-426b-ad56-9f523b228322","name":"user_number","value":"={{ $(''Texto_o_Audio?'').item.json.user_number }}","type":"string"},{"id":"006894ab-1a68-4638-9704-d1a2f703b6f8","name":"platform","value":"={{ $(''Texto_o_Audio?'').item.json.platform }}","type":"string"}]},"options":{}},"type":"n8n-nodes-base.set","typeVersion":3.4,"position":[0,0],"id":"c79a0a40-91bc-4d24-a10e-c26f6a39ff15","name":"Agrupar_texto_acumulado_resto_variables_enviar"},{"parameters":{"method":"POST","url":"https://lead.integraia.lat/api/session/consultar","sendBody":true,"bodyParameters":{"parameters":[{"name":"session_id","value":"={{ $json.session_id }}"}]},"options":{}},"type":"n8n-nodes-base.httpRequest","typeVersion":4.3,"position":[496,928],"id":"1af22aac-8ca8-4250-817d-f8a10ab63065","name":"Consultar_estado_Odoo","alwaysOutputData":true,"onError":"continueErrorOutput"},{"parameters":{"jsCode":"// =============================================\n// UNIR DATOS DE AMBOS NODOS - FORMATO ESPECÍFICO\n// =============================================\n\n// 1. Obtener datos de Preparar_Input_AI (primer elemento del merge)\nconst datosPrepararInput = $input.all()[0]?.json || {};\n\n// 2. Obtener datos de Consultar_estado_Odoo (segundo elemento del merge)\n// La respuesta de Odoo viene como array: [{...}]\nlet datosOdoo = $input.all()[1]?.json;\nif (Array.isArray(datosOdoo) && datosOdoo.length > 0) {\n    datosOdoo = datosOdoo[0];\n} else {\n    datosOdoo = datosOdoo || {};\n}\n\nconsole.log(\"📥 DATOS DE ODOO (crudo):\", JSON.stringify($input.all()[1]?.json, null, 2));\nconsole.log(\"📥 DATOS DE ODOO (procesado):\", JSON.stringify(datosOdoo, null, 2));\n\n// 3. Extraer el estado_anterior - AHORA SE LLAMA \"estado\" en lugar de \"debug_estado_nuevo\"\nconst estado_anterior = datosOdoo.estado || null;\nconst modoOdoo = estado_anterior?.modo || datosOdoo.modo || null;\nconst pasoOdoo = estado_anterior?.paso || datosOdoo.paso || null;\n\n// 4. Crear el resultado en el formato EXACTO solicitado\nconst resultadoFinal = {\n    // Campos de Preparar_Input_AI\n    text: datosPrepararInput.text || \"0\",\n    session_id: datosPrepararInput.session_id || \"\",\n    image_url: datosPrepararInput.image_url || \"\",\n    platform: datosPrepararInput.platform || \"whatsapp\",\n    account_id: datosPrepararInput.account_id || \"\",\n    conversation_id: datosPrepararInput.conversation_id || \"\",\n    \n    // Campos de Odoo (estado_anterior completo)\n    estado_anterior: estado_anterior,\n    \n    // Campos adicionales de Odoo (modo y paso al nivel raíz también)\n    modo: modoOdoo,\n    paso: pasoOdoo,\n    \n    // Datos paciente para fácil acceso\n    datos_paciente: estado_anterior?.datos_paciente || {}\n};\n\n// 5. Si estado_anterior es null, crear estructura básica\nif (!estado_anterior) {\n    resultadoFinal.estado_anterior = {\n        modo: datosOdoo.modo || null,\n        paso: datosOdoo.paso || null,\n        datos_paciente: {},\n        timestamp: null\n    };\n}\n\nconsole.log(\"✅ RESULTADO FINAL:\");\nconsole.log(JSON.stringify(resultadoFinal, null, 2));\n\nreturn [{ json: resultadoFinal }];"},"type":"n8n-nodes-base.code","typeVersion":2,"position":[832,720],"id":"9a40fa92-6936-4a26-82f1-ab83004e14d9","name":"Procesar_respuesta_Odoo"},{"parameters":{},"type":"n8n-nodes-base.merge","typeVersion":3.2,"position":[640,720],"id":"28fceab3-8653-49a1-b6d1-0005960c28da","name":"Combinar_entrada_session_odoo"},{"parameters":{"conditions":{"options":{"caseSensitive":true,"leftValue":"","typeValidation":"strict","version":3},"conditions":[{"id":"abec1745-9884-494b-b11e-d7a2c6cf74b6","leftValue":"={{ $json.modo }}","rightValue":"AGENDANDO_CITA","operator":{"type":"string","operation":"equals"}},{"id":"bdb76473-e091-401d-8445-4b3e20b1fac5","leftValue":"={{ $json.paso }}","rightValue":"SOLICITAR_TELEFONO","operator":{"type":"string","operation":"equals"}}],"combinator":"and"},"options":{}},"type":"n8n-nodes-base.if","typeVersion":2.3,"position":[944,992],"id":"0d3081d1-4b4f-4e8c-9e2d-beb98b4fa399","name":"If1"},{"parameters":{"jsCode":"// =============================================\n// PROCESADOR SIMPLIFICADO DE RESULTADO DE BÚSQUEDA - INTERNACIONAL\n// =============================================\n\ntry {\n  // 1. OBTENER DATOS DE ENTRADA\n  const datosEntrada = $json || {};\n  \n  console.log(\"=== PROCESADOR DE BÚSQUEDA - ENTRADA ===\");\n  console.log(\"Tipo de entrada:\", typeof datosEntrada);\n  console.log(\"Es array?:\", Array.isArray(datosEntrada));\n  console.log(\"Contenido entrada:\", JSON.stringify(datosEntrada, null, 2));\n\n  // Variables por defecto\n  let estado_anterior = {\n    modo: \"AGENDANDO_CITA\",\n    paso: \"SOLICITAR_TELEFONO\",\n    timestamp: new Date().toISOString(),\n    datos_paciente: {}\n  };\n\n  let datos_paciente = {};\n  let siguiente_paso = \"SOLICITAR_TELEFONO\";\n  let respuesta = \"\";\n  let modo = \"AGENDANDO_CITA\";\n  let telefono_buscado = null;\n\n  // Función para validar teléfono internacional (formato E.164)\n  function validarTelefonoInternacional(telefono) {\n    if (!telefono) return false;\n    \n    // Remover espacios y otros caracteres\n    const telefonoLimpio = telefono.toString().trim();\n    \n    // Validar formato E.164: + seguido de 7 a 15 dígitos\n    // Ejemplos: +584141234567, +12124567890, +34600123456\n    const regexE164 = /^\\+\\d{7,15}$/;\n    \n    // Validar sin espacios\n    if (regexE164.test(telefonoLimpio.replace(/\\s/g, ''''))) {\n      return true;\n    }\n    \n    // Validar con espacios: +58 412 1234567, +1 212 456 7890\n    const regexConEspacios = /^\\+\\d{1,3}(\\s?\\d{3,4}){2,4}$/;\n    return regexConEspacios.test(telefonoLimpio);\n  }\n\n  // Función para extraer solo los números de un teléfono (incluyendo el +)\n  function extraerNumerosTelefono(telefono) {\n    if (!telefono) return null;\n    \n    // Mantener el signo + y los números\n    const telefonoLimpio = telefono.toString().trim();\n    \n    // Si comienza con +, mantenerlo y extraer solo números después\n    if (telefonoLimpio.startsWith(''+'')) {\n      const codigoPais = telefonoLimpio.match(/^\\+\\d{1,3}/)?.[0] || ''+'';\n      const numerosRestantes = telefonoLimpio.slice(codigoPais.length).replace(/\\D/g, '''');\n      return codigoPais + numerosRestantes;\n    }\n    \n    // Si no tiene +, solo extraer números\n    return ''+'' + telefonoLimpio.replace(/\\D/g, '''');\n  }\n\n  // 2. BUSCAR EL ARRAY DE RESULTADO EN LA ENTRADA\n  let resultadoArray = null;\n\n  if (Array.isArray(datosEntrada)) {\n    resultadoArray = datosEntrada;\n    console.log(\"✅ Entrada detectada como array directo\");\n  } else if (typeof datosEntrada === ''object'') {\n    for (const key in datosEntrada) {\n      if (Array.isArray(datosEntrada[key])) {\n        resultadoArray = datosEntrada[key];\n        console.log(`✅ Array encontrado en propiedad: ${key}`);\n        break;\n      }\n    }\n    \n    if (!resultadoArray && datosEntrada.existe !== undefined) {\n      resultadoArray = [datosEntrada];\n      console.log(\"✅ Objeto de paciente convertido a array\");\n    }\n  }\n\n  // 3. PROCESAR EL RESULTADO\n  if (resultadoArray && resultadoArray.length > 0) {\n    const resultado = resultadoArray[0];\n    \n    // Extraer el teléfono buscado de diferentes campos posibles\n    telefono_buscado = resultado.telefono_buscado || resultado.telefono || null;\n    \n    // Validar si el teléfono buscado tiene un formato válido\n    const telefonoValido = validarTelefonoInternacional(telefono_buscado);\n    const telefonoFormateado = extraerNumerosTelefono(telefono_buscado);\n    \n    console.log(\"📞 Teléfono buscado:\", telefono_buscado);\n    console.log(\"✅ Teléfono válido?\", telefonoValido);\n    console.log(\"🔢 Teléfono formateado:\", telefonoFormateado);\n    \n    if (resultado.existe === true) {\n      console.log(\"✅ PACIENTE ENCONTRADO EN EL SISTEMA\");\n      \n      // Cargar datos del paciente\n      datos_paciente = {\n        nombre: resultado.nombre_completo || null,\n        cedula: resultado.cedula || null,\n        telefono: telefonoFormateado || resultado.telefono || null,\n        fecha_nacimiento: resultado.fecha_nacimiento || null,\n        paciente_nuevo: \"SI\"\n      };\n      \n      siguiente_paso = \"SOLICITAR_MEDIO_PAGO\";\n      \n      // Llenar también el estado_anterior.datos_paciente\n      estado_anterior.datos_paciente = { ...datos_paciente };\n      \n      respuesta = `✅ **TUS DATOS HAN SIDO CARGADOS AUTOMÁTICAMENTE**\\n\\n` +\n        `🔍 Encontramos tu información en el sistema:\\n\\n` +\n        `• Nombre: ${datos_paciente.nombre}\\n` +\n        `• Cédula: ${datos_paciente.cedula}\\n` +\n        `• Fecha de nacimiento: ${datos_paciente.fecha_nacimiento}\\n` +\n        `• Teléfono: ${datos_paciente.telefono || ''No cargado''}\\n\\n` +\n        `🏥 Eres paciente nuevo\\n\\n` +\n        `💳 Ahora necesito saber tu medio de pago:\\n\\nEscribe:\\n• PARTICULAR - para pago directo\\n• SEGURO - si tienes seguro médico`;\n      \n    } else {\n      // PACIENTE NO ENCONTRADO\n      console.log(\"❌ PACIENTE NO ENCONTRADO EN EL SISTEMA\");\n      \n      // Verificar si el teléfono buscado es válido\n      if (telefonoValido && telefonoFormateado && telefonoFormateado.length >= 8) {\n        // Teléfono válido: paciente no encontrado, proceder a registro\n        respuesta = resultado.mensaje || \n          `❌ No encontré datos registrados con el teléfono ${telefono_buscado}.\\n\\n` +\n          `📋 Por favor, escribe tu cédula (solo números) para continuar con el registro:`;\n        \n        siguiente_paso = \"SOLICITAR_CEDULA\";\n        \n        // Llenar datos_paciente con el teléfono validado\n        datos_paciente = {\n          telefono: telefonoFormateado\n        };\n        \n        console.log(\"📝 Procediendo a registro con teléfono válido\");\n      } else {\n        // Teléfono inválido: volver a solicitar teléfono\n        respuesta = `❌ El número de teléfono \"${telefono_buscado || ''proporcionado''}\" no tiene un formato válido.\\n\\n` +\n          `📞 Por favor, envía tu número de teléfono en formato internacional:\\n` +\n          `• Comienza con + seguido del código de país\\n` +\n          `• Luego tu número de teléfono\\n\\n` +\n          `Ejemplos:\\n` +\n          `• Venezuela: +584141234567\\n` +\n          `• Estados Unidos: +12124567890\\n` +\n          `• España: +34600123456\\n` +\n          `• Colombia: +573001234567\\n` +\n          `• México: +5215512345678\\n\\n` +\n          `También puedes usar espacios:\\n` +\n          `• +58 412 1234567\\n` +\n          `• +1 212 456 7890`;\n        \n        siguiente_paso = \"SOLICITAR_TELEFONO\";\n        \n        // Limpiar datos del paciente\n        datos_paciente = {\n          telefono: null\n        };\n        \n        console.log(\"🔄 Teléfono inválido, volviendo a SOLICITAR_TELEFONO\");\n      }\n      \n      // estado_anterior.datos_paciente se queda vacío\n      estado_anterior.datos_paciente = {};\n    }\n  } else {\n    // Sin resultado válido\n    siguiente_paso = \"SOLICITAR_TELEFONO\";\n    respuesta = `❌ No se pudo procesar la búsqueda.\\n\\n` +\n      `📞 Por favor, envía tu número de teléfono en formato internacional:\\n` +\n      `• Comienza con + seguido del código de país\\n` +\n      `• Luego tu número de teléfono\\n\\n` +\n      `Ejemplos:\\n` +\n      `• Venezuela: +584141234567\\n` +\n      `• Estados Unidos: +12124567890\\n` +\n      `• España: +34600123456`;\n    \n    datos_paciente = {\n      telefono: null\n    };\n    \n    estado_anterior.datos_paciente = {};\n  }\n\n  // 4. CONSTRUIR SALIDA\n  const salida = {\n    respuesta: respuesta,\n    estado_anterior: estado_anterior,\n    modo: modo,\n    paso: siguiente_paso,\n    datos_paciente: datos_paciente\n  };\n\n  console.log(\"=== SALIDA FINAL ===\");\n  console.log(\"Paso siguiente:\", siguiente_paso);\n  console.log(\"Datos paciente:\", JSON.stringify(datos_paciente, null, 2));\n  console.log(\"Salida generada:\", JSON.stringify(salida, null, 2));\n\n  return [salida];\n\n} catch (error) {\n  console.error(\"ERROR en procesador de búsqueda:\", error);\n  \n  // En caso de error, devolver estructura básica\n  const salida_error = {\n    respuesta: \"⚠️ Hubo un error al procesar la búsqueda.\\n\\n📞 Por favor, envía tu número de teléfono en formato internacional (con + y código de país). Ejemplo: +584141234567\",\n    estado_anterior: {\n      modo: \"AGENDANDO_CITA\",\n      paso: \"SOLICITAR_TELEFONO\",\n      timestamp: new Date().toISOString(),\n      datos_paciente: {}\n    },\n    modo: \"AGENDANDO_CITA\",\n    paso: \"SOLICITAR_TELEFONO\",\n    datos_paciente: {}\n  };\n\n  return [salida_error];\n}\n"},"type":"n8n-nodes-base.code","typeVersion":2,"position":[1424,976],"id":"37a0ae1f-5d41-42eb-a614-3b5e18849aa5","name":"Paso_a_ejecutar"},{"parameters":{"method":"POST","url":"https://lead.integraia.lat/chat-bot-unisa/buscar_por_telefono_http","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Content-Type","value":"application/json"}]},"sendBody":true,"specifyBody":"json","jsonBody":"={\n  \"telefono\": \"{{$json.text }}\"\n}","options":{}},"type":"n8n-nodes-base.httpRequest","typeVersion":4.3,"position":[1200,976],"id":"ac901a38-9d21-4fb2-8db0-3b65e13eebc3","name":"BUSCAR_TELEFONO","alwaysOutputData":true,"onError":"continueRegularOutput"},{"parameters":{},"type":"n8n-nodes-base.merge","typeVersion":3.2,"position":[1712,736],"id":"132938a7-1935-4c2a-966e-eb86cb6e9125","name":"Combinar_entrada_session_odoo1"},{"parameters":{},"type":"n8n-nodes-base.manualTrigger","typeVersion":1,"position":[-1840,800],"id":"24b142f2-73f7-47a5-9f19-f6afd85da44e","name":"When clicking ‘Execute workflow’"},{"parameters":{"assignments":{"assignments":[{"id":"5b9b41b4-ef98-4699-80eb-24e70dbee117","name":"text","value":"={{ $json.content }}","type":"string"},{"id":"0f98afd1-e2e6-4c4d-9e9f-6e38c87694c6","name":"session_id","value":"={{ $json.session_id }}","type":"string"},{"id":"9cbd2d29-4e32-46fd-bbea-88317ec7681d","name":"account_id","value":"={{ $json.account_id }}","type":"string"},{"id":"ddcd14fb-bfd1-4f23-a0e0-7d0fa54e8719","name":"conversation_id","value":"={{ $json.conversation_id }}","type":"string"},{"id":"9052a8a2-5a39-4b6f-a44f-728e2e7c2c41","name":"message_type","value":"={{ $json.message_type }}","type":"string"},{"id":"c76e6bbf-22cf-4dd8-ae67-49c5801c5be1","name":"user_name","value":"={{ $json.user_name }}","type":"string"},{"id":"b16fbd53-b6a3-4e0b-ac12-01912379a2fc","name":"user_number","value":"={{ $json.user_number }}","type":"string"},{"id":"5e7f1bef-2e33-448d-b2dd-8aa060685c18","name":"user_message","value":"={{ $json.content }}","type":"string"},{"id":"image_url_assignment","name":"image_url","value":"={{ $json.image_url || '''' }}","type":"string"},{"id":"cd2eb5de-c51c-4890-8f5c-d333c70ea366","name":"platform","value":"={{ $json.platform }}","type":"string"},{"id":"02590fd2-331a-4e3c-bd8b-5b23fe1645b8","name":"channel","value":"={{ $json.channel }}","type":"string"}]},"options":{}},"type":"n8n-nodes-base.set","typeVersion":3.4,"position":[-1600,192],"id":"39739e80-bcb6-44f2-98dc-e03a47d403ea","name":"Obtener_Info"},{"parameters":{"inputSource":"jsonExample","jsonExample":"{\n  \"text\": \"quiero una cita\",\n  \"session_id\": \"123\",\n  \"account_id\": \"1\",\n  \"conversation_id\": \"7\",\n  \"message_type\": \"text\",\n  \"user_name\": \"\",\n  \"user_number\": \"\",\n  \"platform\": \"whatsapp\",\n  \"channel\": \"whatsapp\",\n  \"content\": \"quiero una cita\",\n  \"file_type\": null,\n  \"phone_number\": null,\n  \"user_message\": \"quiero una cita\",\n  \"image_url\": \"image_url\",\n  \"agente_desactivado\": false\n}"},"type":"n8n-nodes-base.executeWorkflowTrigger","typeVersion":1.1,"position":[-1888,544],"id":"db16cee9-162c-4ee7-a9b3-1e4ac1d29f80","name":"answer-chastwoot"},{"parameters":{"jsCode":"// =============================================\n// COMBINADOR OPTIMIZADO CON ESTADO_ACTUAL - VERSIÓN CORREGIDA\n// =============================================\n\ntry {\n  // Obtener las dos entradas del Merge (siempre llegan en este orden)\n  const entrada1 = $input.all()[0]?.json || {};  // Contexto de la conversación\n  const entrada2 = $input.all()[1]?.json || {};  // Resultado del procesador de búsqueda\n  \n  console.log(\"=== COMBINADOR CON ESTADO_ACTUAL ===\");\n  console.log(\"Entrada 1 (contexto):\", JSON.stringify(entrada1, null, 2));\n  console.log(\"Entrada 2 (procesador):\", JSON.stringify(entrada2, null, 2));\n\n  // Función auxiliar para verificar si un valor está realmente vacío\n  function estaVacio(valor) {\n    if (valor === null || valor === undefined) return true;\n    if (typeof valor === ''string'') return valor.trim() === '''';\n    if (typeof valor === ''object'' && !Array.isArray(valor)) {\n      return Object.keys(valor).length === 0;\n    }\n    return false;\n  }\n\n  // 1. DETERMINAR MODO Y PASO (dar prioridad a la segunda entrada si existe)\n  let modo, paso;\n  \n  if (!estaVacio(entrada2)) {\n    // Usar modo y paso de la segunda entrada (prioridad)\n    modo = entrada2.modo || \"\";\n    paso = entrada2.paso || \"\";\n    \n    console.log(\"Usando modo y paso de entrada2:\", { modo, paso });\n  } else {\n    // Si no hay segunda entrada, usar modo y paso de la primera entrada\n    modo = entrada1.modo || \"\";\n    paso = entrada1.paso || \"\";\n    \n    console.log(\"Usando modo y paso de entrada1:\", { modo, paso });\n  }\n\n  // 2. DETERMINAR DATOS_PACIENTE (combinar ambos)\n  let datos_paciente = {};\n  \n  // Primero tomar los datos_paciente de la primera entrada\n  if (entrada1.datos_paciente && !estaVacio(entrada1.datos_paciente)) {\n    datos_paciente = { ...entrada1.datos_paciente };\n    console.log(\"Datos paciente iniciales de entrada1:\", datos_paciente);\n  }\n  \n  // Luego sobrescribir/agregar con los datos de la segunda entrada\n  if (entrada2.datos_paciente && !estaVacio(entrada2.datos_paciente)) {\n    datos_paciente = { ...datos_paciente, ...entrada2.datos_paciente };\n    console.log(\"Datos paciente actualizados con entrada2:\", datos_paciente);\n  }\n\n  // 3. CONSTRUIR ESTADO_ACTUAL\n  const timestamp = new Date().toISOString();\n  \n  const estado_actual = {\n    modo: modo,\n    paso: paso,\n    timestamp: timestamp,\n    datos_paciente: datos_paciente\n  };\n\n  // 4. CONSTRUIR RESULTADO FINAL\n  const resultado = {\n    // Campos de contexto (siempre de la primera entrada)\n    text: entrada1.text || \"\",\n    session_id: entrada1.session_id || \"\",\n    image_url: entrada1.image_url || \"\",\n    platform: entrada1.platform || \"whatsapp\",\n    account_id: entrada1.account_id || \"\",\n    conversation_id: entrada1.conversation_id || \"\",\n    \n    // Estado actual\n    estado_actual: estado_actual\n    \n    \n  };\n\n  console.log(\"=== SALIDA FINAL ===\");\n  console.log(\"Resultado generado:\", JSON.stringify(resultado, null, 2));\n\n  return [resultado];\n\n} catch (error) {\n  console.error(\"ERROR en combinador:\", error);\n  \n  // Estructura de error con estado_actual\n  const timestamp = new Date().toISOString();\n  const estado_actual_error = {\n    modo: \"\",\n    paso: \"\",\n    timestamp: timestamp,\n    datos_paciente: {}\n  };\n  \n  return [{\n    text: \"\",\n    session_id: \"\",\n    image_url: \"\",\n    platform: \"whatsapp\",\n    account_id: \"1\",\n    conversation_id: \"7\",\n    estado_actual: estado_actual_error\n  }];\n}"},"type":"n8n-nodes-base.code","typeVersion":2,"position":[1952,736],"id":"76e87966-aed1-4273-8f40-dbe9c48376ab","name":"salida"},{"parameters":{"content":"## Si es la primera vez SOLICITAR_TELEFONO buscando el teléfono, entonces llenamos ya variables que estén en nuestra BD, de lo contrario la pediremos.\n## A. PACIENTE ENCONTRADO (existe === true)\nCarga automáticamente los datos del paciente\n\nSiguiente paso: SOLICITAR_MEDIO_PAGO\n\nRespuesta: Muestra datos del paciente y pregunta por método de pago\n\nDatos obtenidos: nombre, cédula, teléfono, fecha_nacimiento\n\n## B. PACIENTE NO ENCONTRADO (existe !== true)\nSi teléfono es válido:\n\nSOLICITAR_CEDULA para registro nuevo\n\nGuarda el teléfono validado\n\nSi teléfono es inválido:\n\nSOLICITAR_TELEFONO de nuevo\n\nMuestra ejemplos de formato correcto\n\n## C. SIN RESULTADOS VÁLIDOS\nVuelve a SOLICITAR_TELEFONO","height":640,"width":1072},"type":"n8n-nodes-base.stickyNote","position":[768,928],"typeVersion":1,"id":"9aec14ed-c4df-4423-babd-46d465641253","name":"Sticky Note"}]', '{"Audio_a_Texto_whatsapp":{"main":[[{"node":"Extraer_Texto_Audio","type":"main","index":0}]]},"Get File Data":{"main":[[{"node":"Audio_a_Texto_whatsapp","type":"main","index":0}]]},"Texto_o_Audio?":{"main":[[{"node":"Obtener_Info","type":"main","index":0}],[{"node":"Get File Data","type":"main","index":0}],[{"node":"Procesar_Imagen_whatsapp","type":"main","index":0}]]},"Procesar_Imagen_whatsapp":{"main":[[{"node":"Preparar_Input_AI","type":"main","index":0}]]},"Extraer_Texto_Audio":{"main":[[{"node":"Merge","type":"main","index":1}]]},"Preparar_Input_AI":{"main":[[{"node":"Consultar_estado_Odoo","type":"main","index":0},{"node":"Combinar_entrada_session_odoo","type":"main","index":0}]]},"Buffer":{"main":[[{"node":"Wait","type":"main","index":0}]]},"Wait":{"main":[[{"node":"Get_buffer_data","type":"main","index":0}]]},"Get_buffer_data":{"main":[[{"node":"If","type":"main","index":0}]]},"If":{"main":[[{"node":"Agrupar_texto_acumulado_resto_variables_enviar","type":"main","index":0}],[{"node":"No Operation, do nothing","type":"main","index":0}]]},"Merge":{"main":[[{"node":"Buffer","type":"main","index":0}]]},"Borrar_mensajes_buffer":{"main":[[{"node":"Preparar_Input_AI","type":"main","index":0}]]},"Agrupar_texto_acumulado_resto_variables_enviar":{"main":[[{"node":"Borrar_mensajes_buffer","type":"main","index":0}]]},"Consultar_estado_Odoo":{"main":[[{"node":"Combinar_entrada_session_odoo","type":"main","index":1}]]},"Combinar_entrada_session_odoo":{"main":[[{"node":"Procesar_respuesta_Odoo","type":"main","index":0}]]},"If1":{"main":[[{"node":"BUSCAR_TELEFONO","type":"main","index":0}]]},"Procesar_respuesta_Odoo":{"main":[[{"node":"If1","type":"main","index":0},{"node":"Combinar_entrada_session_odoo1","type":"main","index":0}]]},"BUSCAR_TELEFONO":{"main":[[{"node":"Paso_a_ejecutar","type":"main","index":0}]]},"Paso_a_ejecutar":{"main":[[{"node":"Combinar_entrada_session_odoo1","type":"main","index":1}]]},"Combinar_entrada_session_odoo1":{"main":[[{"node":"salida","type":"main","index":0}]]},"Obtener_Info":{"main":[[{"node":"Merge","type":"main","index":0}]]},"answer-chastwoot":{"main":[[{"node":"Texto_o_Audio?","type":"main","index":0}]]},"When clicking ‘Execute workflow’":{"main":[[{"node":"Texto_o_Audio?","type":"main","index":0}]]}}', '2026-03-03 19:48:29.776+00', '2026-03-03 22:30:49.763+00', '{"executionOrder":"v1","availableInMCP":false}', NULL, '{"When clicking ‘Execute workflow’":[{"json":{"session_id":"584142711347","account_id":"1","conversation_id":"7","message_type":"incoming","user_name":"saymon","user_number":"+584142711347","platform":"whatsapp","channel":"Channel::Whatsapp","file_type":"audio","phone_number":"+584142711347","image_url":"https://chatwoot.jumpjibe.com/rails/active_storage/blobs/redirect/eyJfcmFpbHMiOnsibWVzc2FnZSI6IkJBaHBBcEFCIiwiZXhwIjpudWxsLCJwdXIiOiJibG9iX2lkIn19--8e62b21c8f5c741fb82025f60c1529bee58645a2/File.ogg","agente_desactivado":"on"}}]}', '100b6f4f-5a0e-492e-8a58-0809466f4d8f', 0, 'vWJpmkfeJohc6Ff4', NULL, 'edK6v13CZSNAYTJi', false, 50, NULL, NULL);
INSERT INTO public.workflow_entity (name, active, nodes, connections, "createdAt", "updatedAt", settings, "staticData", "pinData", "versionId", "triggerCount", id, meta, "parentFolderId", "isArchived", "versionCounter", description, "activeVersionId") VALUES ('tool_citas-deprecated', false, '[{"parameters":{"promptType":"define","text":"={{ $json.text }}","options":{"systemMessage":"=// =====================================================\n// BOT UNISA - FLUJO PRINCIPAL OPTIMIZADO\n// =====================================================\n\n// FECHA ACTUAL: {{ $now }}\n// PLATAFORMA: {{ $json.platform }}\n// SESIÓN: {{ $json.session_id }}\n\n// =====================================================\n// INICIALIZACIÓN - SIN MEMORIA ENTRE MENSAJES\n// =====================================================\n\n// Variables de estado para esta ejecución (no persistir)\nlet paso_actual = \"INICIO\";\nlet contexto = \"TITULAR\";\n\nlet paciente = {\n    telefono: \"\",\n    cedula: \"\",\n    nombre_completo: \"\",\n    fecha_nacimiento: \"\",\n    paciente_nuevo: \"\"\n};\n\nlet medio_pago = \"\";\nlet servicio = \"\";\nlet fecha_cita = \"\";\nlet hora_cita = \"\";\nlet membresia_interes = \"\";\nlet fotos_cedula = [];\nlet imagenes_adicionales = [];\n\nlet captura_realizada = false;\nlet esperando_confirmacion = false;\n\n// =====================================================\n// FUNCIONES DE APOYO\n// =====================================================\n\nfunction normalizarTelefono(t) {\n    if (!t) return null;\n    t = t.trim().replace(/\\s+/g, '''');\n    if (/^0\\d{10}$/.test(t)) return \"+58\" + t.substring(1);\n    if (/^\\+58\\d{10}$/.test(t)) return t;\n    if (/^58\\d{10}$/.test(t)) return \"+\" + t;\n    if (/^\\d{10}$/.test(t)) return \"+58\" + t;\n    return null;\n}\n\nfunction esUrlValida(url) {\n    return url && url.startsWith(''http'');\n}\n\n// =====================================================\n// MANEJO DE ENTRADA DEL USUARIO\n// =====================================================\n\nconst text = {{ $json.text }};\nconst platform = {{ $json.platform }};\nconst session_id = {{ $json.session_id }};\nconst current_image_url = {{ $json.current_image_url || '''' }};\nconst image_url = {{ $json.image_url || '''' }};\n\n// =====================================================\n// DETECCIÓN DE INTENCIÓN INICIAL\n// =====================================================\n\n// Si el usuario envía saludo inicial\nif (text.toLowerCase().includes(''hola'') || \n    text.toLowerCase().includes(''buenas'') || \n    text.toLowerCase().includes(''buenos'')) {\n    \n    return `¡Hola! 😊 Bienvenido/a a UNISA, tu Unidad de Salud Integral.  \nSoy BOT UNISA, tu asistente virtual disponible las 24 horas.\n\n¿Qué necesitas hoy? Puedes escribirme directamente:  \n💲 Precios  \n🩺 Servicios que ofrecemos  \n📅 Agendar cita / laboratorio / estudios  \n💙 Tarjeta de la Salud o CREDIUNISA  \n❓ Otra consulta  \n\n¡Estoy aquí para ayudarte!`;\n}\n\n// Si el usuario quiere agendar cita (cualquier variación)\nif (text.toLowerCase().includes(''agendar'') || \n    text.toLowerCase().includes(''cita'') ||\n    text.toLowerCase().includes(''reservar'') ||\n    text.toLowerCase().includes(''consulta'') ||\n    text.toLowerCase().includes(''quiero una cita'') ||\n    text.toLowerCase().includes(''necesito cita'')) {\n    \n    paso_actual = \"SOLICITAR_TELEFONO\";\n    return ''📱 Para agendar una cita, necesito tu número de WhatsApp con código de país.\\n\\nEjemplo: +584123456789\\n\\nPor favor, escríbelo a continuación:'';\n}\n\n// Si el usuario pide precios\nif (text.toLowerCase().includes(''precio'') || \n    text.toLowerCase().includes(''valor'') || \n    text.toLowerCase().includes(''cuesta'') ||\n    text.toLowerCase().includes(''cuánto'')) {\n    \n    return ''💲 **PRECIOS UNISA 2025**\\n\\n• Consulta médica general → 25 USD\\n• Rayos X (cualquier proyección) → 10 USD\\n• Mamografía sin implantes → 20 USD\\n• Mamografía con implantes → 30 USD\\n\\n💙 Pregúntame por la Tarjeta de la Salud y obtienes hasta 30% de descuento + 1 consulta gratuita al año'';\n}\n\n// Si el usuario pide servicios\nif (text.toLowerCase().includes(''servicio'') || \n    text.toLowerCase().includes(''ofrecen'') ||\n    text.toLowerCase().includes(''qué hacen'')) {\n    \n    return ''🩺 **SERVICIOS UNISA**\\n\\n• Consultas médicas generales y especialidades\\n• Laboratorio clínico\\n• Rayos X digital\\n• Ecografías (general, obstétrica, doppler)\\n• Mamografía\\n• Densitometría ósea\\n• Electrocardiograma y ecocardiograma\\n• Área de Atención Primaria 24/7\\n\\n¿Cuál servicio te interesa?'';\n}\n\n// Si el usuario menciona tarjeta o crédito\nif (text.toLowerCase().includes(''tarjeta'') || \n    text.toLowerCase().includes(''credünisa'') ||\n    text.toLowerCase().includes(''crédito'')) {\n    \n    return ''💙 **TARJETA DE LA SALUD + CREDIUNISA**\\n\\n1. Hasta 30% de descuento en todos los servicios\\n2. 1 consulta gratuita al año\\n3. Vigencia 12 meses\\n4. Costo: 80 USD (20 USD al afiliarte + 6 cuotas de 10 USD)\\n5. Incluye hasta 5 personas\\n6. CREDIUNISA: 100 USD de crédito inmediato en 6 cuotas\\n\\n¿Deseas afiliarte ahora?'';\n}\n\n// =====================================================\n// FLUJO DE AGENDAMIENTO (PASO A PASO)\n// =====================================================\n\n// PASO 1: SOLICITAR TELÉFONO\nif (paso_actual === \"SOLICITAR_TELEFONO\") {\n    const telefono = normalizarTelefono(text);\n    \n    if (!telefono) {\n        return ''❌ Formato incorrecto. Debe ser: +58 seguido de 10 dígitos.\\n\\nEjemplo: +584123456789\\n\\nPor favor, intenta nuevamente:'';\n    }\n    \n    paciente.telefono = telefono;\n    paso_actual = \"BUSCANDO_TELEFONO\";\n    \n    return {\n        tool: \"buscar_por_telefono_http\",\n        parameters: { telefono: telefono },\n        message: `🔍 Buscando información para el número ${telefono}...`\n    };\n}\n\n// PASO 2: PROCESAR RESULTADO DE BÚSQUEDA\nif (paso_actual === \"BUSCANDO_TELEFONO\") {\n    // Verificar si existe y tiene datos completos\n    if ({{ $json.existe === true && $json.cedula && $json.nombre_completo && $json.fecha_nacimiento }}) {\n        paciente.cedula = {{ $json.cedula }};\n        paciente.nombre_completo = {{ $json.nombre_completo }};\n        paciente.fecha_nacimiento = {{ $json.fecha_nacimiento }};\n        paso_actual = \"CONFIRMAR_DATOS\";\n        \n        return `✅ **ENCONTRAMOS TUS DATOS**\\n\\n• 👤 Nombre: {{ $json.nombre_completo }}\\n• 🆔 Cédula: {{ $json.cedula }}\\n• 🎂 Fecha nacimiento: {{ $json.fecha_nacimiento }}\\n\\n¿Son correctos? (Responde SI o NO)`;\n    } else {\n        // No encontrado o datos incompletos\n        paso_actual = \"SOLICITAR_CEDULA\";\n        return ''📋 No encontramos un registro completo. Para crear uno nuevo, necesito:\\n\\n**1. Tu número de cédula (solo números):**'';\n    }\n}\n\n// PASO 3: CONFIRMAR DATOS ENCONTRADOS\nif (paso_actual === \"CONFIRMAR_DATOS\") {\n    if (text.toUpperCase() === ''SI'' || text.toUpperCase() === ''SÍ'') {\n        paso_actual = \"SOLICITAR_MEDIO_PAGO\";\n        return ''💳 **MEDIO DE PAGO**\\n\\n¿Cómo deseas pagar?\\n\\n• PARTICULAR - Pago directo\\n• SEGURO - Con seguro médico'';\n    } else if (text.toUpperCase() === ''NO'') {\n        paso_actual = \"SOLICITAR_CEDULA\";\n        return ''📋 **ACTUALIZAR DATOS**\\n\\nPor favor, ingresa tu número de cédula (solo números):'';\n    } else {\n        return ''❓ Por favor, responde SI o NO:\\n\\n¿Los datos son correctos?'';\n    }\n}\n\n// PASO 4: SOLICITAR CÉDULA (NUEVO REGISTRO)\nif (paso_actual === \"SOLICITAR_CEDULA\") {\n    if (!text.trim() || !/^\\d+$/.test(text.trim())) {\n        return ''❌ Por favor, ingresa solo números.\\n\\n**Tu cédula (solo números):**'';\n    }\n    \n    paciente.cedula = text.trim();\n    paso_actual = \"SOLICITAR_NOMBRE\";\n    return ''👤 **NOMBRE COMPLETO**\\n\\nAhora ingresa tu nombre completo:'';\n}\n\n// PASO 5: SOLICITAR NOMBRE\nif (paso_actual === \"SOLICITAR_NOMBRE\") {\n    if (!text.trim() || text.trim().length < 3) {\n        return ''❌ Nombre muy corto. Ingresa tu nombre completo real:'';\n    }\n    \n    paciente.nombre_completo = text.trim();\n    paso_actual = \"SOLICITAR_FECHA_NACIMIENTO\";\n    return ''🎂 **FECHA DE NACIMIENTO**\\n\\nIngresa tu fecha de nacimiento (dd/mm/aaaa):\\nEjemplo: 15/05/1990'';\n}\n\n// PASO 6: SOLICITAR FECHA DE NACIMIENTO\nif (paso_actual === \"SOLICITAR_FECHA_NACIMIENTO\") {\n    if (!text.trim() || !/\\d{1,2}\\/\\d{1,2}\\/\\d{4}/.test(text.trim())) {\n        return ''❌ Formato incorrecto. Usa dd/mm/aaaa\\n\\nEjemplo: 15/05/1990\\n\\nTu fecha de nacimiento:'';\n    }\n    \n    paciente.fecha_nacimiento = text.trim();\n    paso_actual = \"SOLICITAR_PACIENTE_NUEVO\";\n    return ''🏥 **PRIMERA VEZ EN UNISA**\\n\\n¿Es tu primera vez en UNISA? (Responde SI o NO)'';\n}\n\n// PASO 7: PREGUNTAR SI ES PACIENTE NUEVO\nif (paso_actual === \"SOLICITAR_PACIENTE_NUEVO\") {\n    const respuesta = text.toUpperCase();\n    if (respuesta === ''SI'' || respuesta === ''SÍ'') {\n        paciente.paciente_nuevo = ''SI'';\n    } else if (respuesta === ''NO'') {\n        paciente.paciente_nuevo = ''NO'';\n    } else {\n        return ''❓ Por favor, responde SI o NO:\\n\\n¿Es tu primera vez en UNISA?'';\n    }\n    \n    paso_actual = \"SOLICITAR_MEDIO_PAGO\";\n    return ''💳 **MEDIO DE PAGO**\\n\\n¿Cómo deseas pagar?\\n\\n• PARTICULAR - Pago directo\\n• SEGURO - Con seguro médico'';\n}\n\n// PASO 8: SOLICITAR MEDIO DE PAGO\nif (paso_actual === \"SOLICITAR_MEDIO_PAGO\") {\n    const respuesta = text.toUpperCase();\n    \n    if (respuesta.includes(''PARTICULAR'') || respuesta.includes(''DIRECTO'')) {\n        medio_pago = ''Particular'';\n    } else if (respuesta.includes(''SEGURO'')) {\n        medio_pago = ''Seguro médico'';\n    } else {\n        return ''❌ Opción no reconocida.\\n\\nEscribe:\\n• PARTICULAR - para pago directo\\n• SEGURO - si tienes seguro médico'';\n    }\n    \n    paso_actual = \"SOLICITAR_SERVICIO\";\n    return ''🩺 **SERVICIO REQUERIDO**\\n\\n¿Qué servicio necesitas?\\n\\nEjemplos: Medicina General, Odontología, Laboratorio, Rayos X, etc.'';\n}\n\n// PASO 9: SOLICITAR SERVICIO\nif (paso_actual === \"SOLICITAR_SERVICIO\") {\n    if (!text.trim()) {\n        return ''❌ Por favor, describe el servicio que necesitas:'';\n    }\n    \n    servicio = text.trim();\n    paso_actual = \"SOLICITAR_FECHA_CITA\";\n    return ''📅 **FECHA DESEADA**\\n\\n¿Para qué fecha quieres la cita? (dd/mm/aaaa)\\n\\nTambién puedes escribir:\\n• LO ANTES POSIBLE\\n• ESTA SEMANA\\n• PRÓXIMA SEMANA'';\n}\n\n// PASO 10: SOLICITAR FECHA DE CITA\nif (paso_actual === \"SOLICITAR_FECHA_CITA\") {\n    if (!text.trim()) {\n        return ''❌ Por favor, indica la fecha:'';\n    }\n    \n    fecha_cita = text.trim();\n    paso_actual = \"SOLICITAR_HORA_CITA\";\n    return ''⏰ **HORARIO PREFERIDO**\\n\\n¿Prefieres horario de mañana o tarde?\\n\\nEscribe:\\n• MAÑANA\\n• TARDE\\n• CUALQUIERA'';\n}\n\n// PASO 11: SOLICITAR HORA DE CITA\nif (paso_actual === \"SOLICITAR_HORA_CITA\") {\n    const respuesta = text.toUpperCase();\n    \n    if (respuesta.includes(''MAÑANA'') || respuesta.includes(''MANANA'')) {\n        hora_cita = ''Mañana'';\n    } else if (respuesta.includes(''TARDE'')) {\n        hora_cita = ''Tarde'';\n    } else if (respuesta.includes(''CUALQUIERA'')) {\n        hora_cita = ''Cualquiera'';\n    } else {\n        return ''❌ Opción no válida.\\n\\nEscribe:\\n• MAÑANA\\n• TARDE\\n• CUALQUIERA'';\n    }\n    \n    paso_actual = \"SOLICITAR_MEMBRESIA\";\n    return ''⭐ **MEMBRESÍA UNISA**\\n\\n¿Te interesa conocer los beneficios de nuestra membresía?\\n\\nResponde SI o NO:'';\n}\n\n// PASO 12: PREGUNTAR SOBRE MEMBRESÍA\nif (paso_actual === \"SOLICITAR_MEMBRESIA\") {\n    const respuesta = text.toUpperCase();\n    if (respuesta === ''SI'' || respuesta === ''SÍ'') {\n        membresia_interes = ''SI'';\n    } else if (respuesta === ''NO'') {\n        membresia_interes = ''NO'';\n    } else {\n        return ''❓ Por favor, responde SI o NO:\\n\\n¿Te interesa la membresía?'';\n    }\n    \n    paso_actual = \"SOLICITAR_FOTO_CEDULA\";\n    return ''📸 **FOTO DE CÉDULA**\\n\\n¿Deseas enviar una foto de tu cédula ahora?\\n\\nResponde SI o NO:\\n(Si respondes SI, podrás enviar la imagen en el siguiente mensaje)'';\n}\n\n// PASO 13: MANEJAR FOTO DE CÉDULA\nif (paso_actual === \"SOLICITAR_FOTO_CEDULA\") {\n    if (text.toUpperCase() === ''SI'' || text.toUpperCase() === ''SÍ'') {\n        paso_actual = \"ESPERANDO_FOTO_CEDULA\";\n        return ''📷 Por favor, envía la foto de tu cédula ahora.\\n\\nAsegúrate de que sea clara y legible.'';\n    } else if (text.toUpperCase() === ''NO'') {\n        fotos_cedula = [];\n        paso_actual = \"SOLICITAR_IMAGENES_ADICIONALES\";\n        return ''✅ Continuaremos sin foto de cédula.\\n\\n¿Tienes órdenes médicas, exámenes previos u otros documentos para compartir?\\n\\nResponde SI o NO:'';\n    } else {\n        return ''❓ Por favor, responde SI o NO.\\n\\n¿Deseas enviar una foto de tu cédula?'';\n    }\n}\n\n// PASO 14: MANEJAR RECEPCIÓN DE FOTO DE CÉDULA\nif (paso_actual === \"ESPERANDO_FOTO_CEDULA\") {\n    // Verificar si es una imagen\n    if (current_image_url && current_image_url.startsWith(''http'')) {\n        fotos_cedula = [current_image_url];\n        paso_actual = \"SOLICITAR_IMAGENES_ADICIONALES\";\n        return ''✅ Foto de cédula recibida correctamente.\\n\\n¿Tienes órdenes médicas, exámenes previos u otros documentos para compartir?\\n\\nResponde SI o NO:'';\n    } else {\n        // Si no es una imagen, preguntar de nuevo\n        return ''📷 Esperando la foto de tu cédula. Por favor, envíala ahora o escribe *CANCELAR* para continuar sin ella.'';\n    }\n}\n\n// PASO 15: MANEJAR IMÁGENES ADICIONALES\nif (paso_actual === \"SOLICITAR_IMAGENES_ADICIONALES\") {\n    if (text.toUpperCase() === ''SI'' || text.toUpperCase() === ''SÍ'') {\n        paso_actual = \"ESPERANDO_IMAGENES_ADICIONALES\";\n        return ''📎 Puedes enviar imágenes adicionales ahora.\\n\\nEnvía una por una. Cuando termines, escribe *LISTO*.'';\n    } else if (text.toUpperCase() === ''NO'') {\n        imagenes_adicionales = [];\n        paso_actual = \"MOSTRAR_RESUMEN\";\n    } else {\n        return ''❓ Por favor, responde SI o NO.\\n\\n¿Tienes documentos adicionales para compartir?'';\n    }\n}\n\n// PASO 16: MANEJAR RECEPCIÓN DE IMÁGENES ADICIONALES\nif (paso_actual === \"ESPERANDO_IMAGENES_ADICIONALES\") {\n    if (text.toUpperCase() === ''LISTO'') {\n        paso_actual = \"MOSTRAR_RESUMEN\";\n    } else if (current_image_url && current_image_url.startsWith(''http'')) {\n        imagenes_adicionales.push(current_image_url);\n        return `✅ Imagen adicional recibida (${imagenes_adicionales.length} en total).\\n\\n¿Más imágenes o escribe *LISTO* para continuar?`;\n    } else {\n        return ''📎 Envía otra imagen o escribe *LISTO* para continuar.'';\n    }\n}\n\n// PASO 17: MOSTRAR RESUMEN Y CONFIRMAR\nif (paso_actual === \"MOSTRAR_RESUMEN\") {\n    paso_actual = \"CONFIRMACION_FINAL\";\n    \n    const resumen = `✅ **RESUMEN DE TU SOLICITUD DE CITA**\\n\\n` +\n        `👤 **DATOS PERSONALES**\\n` +\n        `• Nombre: ${paciente.nombre_completo}\\n` +\n        `• Cédula: ${paciente.cedula}\\n` +\n        `• Teléfono: ${paciente.telefono}\\n` +\n        `• Fecha nacimiento: ${paciente.fecha_nacimiento}\\n` +\n        `• Paciente nuevo: ${paciente.paciente_nuevo}\\n\\n` +\n        `📅 **DATOS DE LA CITA**\\n` +\n        `• Servicio: ${servicio}\\n` +\n        `• Fecha deseada: ${fecha_cita}\\n` +\n        `• Horario preferido: ${hora_cita}\\n` +\n        `• Medio de pago: ${medio_pago}\\n` +\n        `• Interés en membresía: ${membresia_interes}\\n\\n` +\n        `📎 **DOCUMENTACIÓN**\\n` +\n        `• Foto de cédula: ${fotos_cedula.length > 0 ? ''✅ Enviada'' : ''❌ No enviada''}\\n` +\n        `• Documentos adicionales: ${imagenes_adicionales.length > 0 ? `✅ ${imagenes_adicionales.length} enviada(s)` : ''❌ No enviados''}\\n\\n` +\n        `🔹 **Para confirmar y agendar escribe:** *CONFIRMAR*\\n` +\n        `🔹 **Para cancelar escribe:** *CANCELAR*`;\n    \n    return resumen;\n}\n\n// PASO 18: CONFIRMACIÓN FINAL\nif (paso_actual === \"CONFIRMACION_FINAL\") {\n    if (text.toUpperCase() === ''CONFIRMAR'') {\n        paso_actual = \"CITA_CONFIRMADA\";\n        \n        // Preparar datos para enviar\n        const datosParaEnviar = {\n            ...paciente,\n            medio_pago: medio_pago,\n            servicio: servicio,\n            fecha_preferida: fecha_cita,\n            hora_preferida: hora_cita,\n            membresia_interes: membresia_interes,\n            foto_cedula_url: fotos_cedula.length > 0 ? fotos_cedula[0] : '''',\n            imagenes_adicionales: imagenes_adicionales.join('',''),\n            plataforma: platform\n        };\n        \n        return {\n            tool: \"capturar_lead_http\",\n            parameters: datosParaEnviar,\n            message: \"🔄 **PROCESANDO TU CITA**\\n\\nEstamos registrando tu información en el sistema...\"\n        };\n    } else if (text.toUpperCase() === ''CANCELAR'') {\n        paso_actual = \"INICIO\";\n        return ''❌ **SOLICITUD CANCELADA**\\n\\nSi deseas agendar una cita en otro momento, escribe *agendar cita*.\\n\\n¡Gracias por contactar a UNISA!'';\n    } else {\n        return ''❓ Por favor, escribe *CONFIRMAR* para agendar o *CANCELAR* para cancelar.'';\n    }\n}\n\n// PASO 19: CITA CONFIRMADA\nif (paso_actual === \"CITA_CONFIRMADA\") {\n    paso_actual = \"INICIO\";\n    return ''🎉 **¡CITA AGENDADA CON ÉXITO!**\\n\\n✅ Tu solicitud ha sido registrada en nuestro sistema.\\n📞 Un ejecutivo de UNISA se contactará contigo pronto para confirmar los detalles finales.\\n\\n¡Gracias por confiar en UNISA! ❤️'';\n}\n\n// =====================================================\n// RESPUESTA POR DEFECTO\n// =====================================================\n\nreturn `¡Hola! 😊 Bienvenido/a a UNISA, tu Unidad de Salud Integral.  \nSoy BOT UNISA, tu asistente virtual disponible las 24 horas.\n\n¿Qué necesitas hoy? Puedes escribirme directamente:  \n💲 Precios  \n🩺 Servicios que ofrecemos  \n📅 Agendar cita / laboratorio / estudios  \n💙 Tarjeta de la Salud o CREDIUNISA  \n❓ Otra consulta  \n\n¡Estoy aquí para ayudarte!`;"}},"type":"@n8n/n8n-nodes-langchain.agent","typeVersion":2.2,"position":[832,-176],"id":"a815bf75-7fcb-4846-bcce-cde4689da623","name":"AI_gent_Citas"},{"parameters":{"model":{"__rl":true,"mode":"list","value":"gpt-4o-mini"},"options":{}},"type":"@n8n/n8n-nodes-langchain.lmChatOpenAi","typeVersion":1.2,"position":[688,128],"id":"811dfae9-1fb3-48ca-9b61-3f2c9eb23924","name":"OpenAI Chat Model","credentials":{"openAiApi":{"id":"SynY9HmZH2SsZkWD","name":"OpenAi account"}}},{"parameters":{"sessionIdType":"customKey","sessionKey":"={{ $json.session_id }}","contextWindowLength":15},"type":"@n8n/n8n-nodes-langchain.memoryBufferWindow","typeVersion":1.3,"position":[880,128],"id":"9009e866-da6c-4f2b-8384-0f7005443bf8","name":"Simple Memory"},{"parameters":{"inputSource":"jsonExample","jsonExample":"{\n \"text\": \"quiero una cita\",\n \"session_id\": \"123\",\n \"platform\": \"whatsapp\",\n\"image_url\":\"image_url\"\n}"},"type":"n8n-nodes-base.executeWorkflowTrigger","typeVersion":1.1,"position":[400,-176],"id":"916702bb-f1ff-4ba4-9d9c-60ceb81f765c","name":"tool_citas"},{"parameters":{"toolDescription":"Busca un paciente en el sistema UNISA usando su número de teléfono. Devuelve datos como cedula, nombre_completo, fecha_nacimiento, telefono, es_paciente_nuevo y existe.","method":"POST","url":"https://jumpjibe.com/chat-bot-unisa/buscar_por_telefono_http","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Content-Type","value":"application/json"}]},"sendBody":true,"bodyParameters":{"parameters":[{"name":"telefono","value":"={{ $fromAI(''telefono'', '''', ''string'') }}"}]},"options":{}},"type":"n8n-nodes-base.httpRequestTool","typeVersion":4.2,"position":[1088,96],"id":"e944ad33-dff0-4fb9-bef9-7bdbc328705c","name":"buscar_por_telefono_http"},{"parameters":{"toolDescription":"Registra un lead/cita en Odoo con todos los datos del paciente. Úsala solo cuando el usuario confirme todo.","method":"POST","url":"https://jumpjibe.com/chat-bot-unisa/capturar_lead_http","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Content-Type","value":"application/json"}]},"sendBody":true,"bodyParameters":{"parameters":[{"name":"cedula","value":"={{ $fromAI(''cedula'', '''', ''string'') }}"},{"name":"telefono","value":"={{ $fromAI(''telefono'', '''', ''string'') }}"},{"name":"nombre_completo","value":"={{ $fromAI(''nombre_completo'', '''', ''string'') }}"},{"name":"fecha_nacimiento","value":"={{ $fromAI(''fecha_nacimiento'', '''', ''string'') }}"},{"name":"plataforma","value":"={{ $json.platform }}"},{"name":"fecha_preferida","value":"={{ $fromAI(''fecha_deseada'', '''', ''string'') }}"},{"name":"hora_preferida","value":"={{ $fromAI(''hora_preferida'', '''', ''string'') }}"},{"name":"servicio","value":"={{ $fromAI(''servicio'', '''', ''string'') }}"},{"name":"medio_pago","value":"={{ $fromAI(''medio_pago'', '''', ''string'') }}"},{"name":"paciente_nuevo","value":"={{ $fromAI(''paciente_nuevo'', '''', ''string'') }}"},{"name":"membresia_interes","value":"={{ $fromAI(''membresia_interes'', '''', ''string'') }}"},{"name":"foto_cedula_url","value":"={{ $fromAI(''foto_cedula_url'', '''', ''string'') }}"},{"name":"imagenes_adicionales","value":"={{ $fromAI(''imagenes_adicionales'', '''', ''string'') }}"}]},"options":{"timeout":30000}},"type":"n8n-nodes-base.httpRequestTool","typeVersion":4.2,"position":[1232,64],"id":"0940b1df-2b33-443f-94e5-1300935ee653","name":"capturar_lead_http"},{"parameters":{"jsCode":"for (const item of $input.all()) {\n  console.log(\"=== DEBUG Verificar_imagen_texto ===\");\n  console.log(\"Texto original:\", item.json.text);\n  console.log(\"image_url original:\", item.json.image_url);\n\n  // **NUEVO: SIEMPRE PASAR current_image_url INCLUSO CUANDO NO HAY IMAGEN**\n  if (item.json.image_url && item.json.image_url.includes(\"http\")) {\n    item.json.text = \"IMAGEN_ENVIADA\";\n    item.json.current_image_url = item.json.image_url;\n    console.log(\"✅ IMAGEN DETECTADA - URL expuesta en current_image_url:\", item.json.current_image_url);\n  } else {\n    if (item.json.text && item.json.text.toLowerCase().trim() === \"saltar\") {\n      item.json.text = \"SALTAR\";\n    }\n    // **NUEVO: SIEMPRE PONER current_image_url AUNQUE SEA VACÍO**\n    item.json.current_image_url = \"\";\n  }\n\n  // **NUEVO: AGREGAR VARIABLES DE VERIFICACIÓN**\n  item.json.debug_image_url = item.json.image_url || \"NO_IMAGE\";\n  item.json.debug_current_url = item.json.current_image_url || \"NO_CURRENT_URL\";\n  \n  console.log(\"Texto final enviado al agente:\", item.json.text);\n  console.log(\"current_image_url final:\", item.json.current_image_url || \"vacío\");\n  console.log(\"debug_image_url:\", item.json.debug_image_url);\n  console.log(\"debug_current_url:\", item.json.debug_current_url);\n  console.log(\"=== FIN DEBUG ===\");\n}\n\nreturn $input.all();"},"type":"n8n-nodes-base.code","typeVersion":2,"position":[592,-176],"id":"314a2c0c-43bd-4e06-97f7-252ef23bcc29","name":"Verificar_imagen_texto"}]', '{"OpenAI Chat Model":{"ai_languageModel":[[{"node":"AI_gent_Citas","type":"ai_languageModel","index":0}]]},"Simple Memory":{"ai_memory":[[{"node":"AI_gent_Citas","type":"ai_memory","index":0}]]},"tool_citas":{"main":[[{"node":"Verificar_imagen_texto","type":"main","index":0}]]},"buscar_por_telefono_http":{"ai_tool":[[{"node":"AI_gent_Citas","type":"ai_tool","index":0}]]},"capturar_lead_http":{"ai_tool":[[{"node":"AI_gent_Citas","type":"ai_tool","index":0}]]},"Verificar_imagen_texto":{"main":[[{"node":"AI_gent_Citas","type":"main","index":0}]]}}', '2025-12-21 20:49:43.2+00', '2026-02-09 16:17:04.831+00', '{"executionOrder":"v1"}', NULL, '{}', '1c7f9f33-