"method":"POST","url":"https://lead.integraia.lat/api/session/guardar","sendBody":true,"specifyBody":"json","jsonBody":"={\n  \"session_id\": \"{{ $json.session_id }}\",\n  \"estado\": {\n    \"modo\": \"{{ $json.estado_actual.modo }}\",\n    \"paso\": \"{{ $json.estado_actual.paso }}\",\n    \"datos_paciente\":{{ JSON.stringify($json.estado_actual.datos_paciente)  }},\n    \"timestamp\": \"{{ $json.estado_actual.timestamp_actividad }}\"\n  }\n} ","options":{}},"type":"n8n-nodes-base.httpRequest","typeVersion":4.3,"position":[3616,2816],"id":"87831292-289c-4a8a-a3f5-45513c3e19bd","name":"Guardar_agendamiento"},{"parameters":{"jsCode":"// Extraer estado actual\nconst estado = $json.estado_actual || {};\nconst datos = estado.datos_paciente || {};\n\n// Construir objeto de salida con nombres originales (SIN prefijo)\nconst output = {\n  // Mensaje e imagen\n  text: $json.text || '''',\n  image_url: $json.image_url || '''',\n\n  // Metadatos de sesión\n  session_id: $json.session_id || '''',\n  conversation_id: $json.conversation_id || '''',\n  account_id: $json.account_id || '''',\n  platform: $json.platform || '''',\n\n  // Estado actual desglosado (plano)\n  modo: estado.modo || null,\n  paso: estado.paso || null,\n  datos_paciente: datos,\n  timestamp_actividad: estado.timestamp_actividad || new Date().toISOString(),\n\n  // Opcional: conservar el estado_actual original por si otros nodos lo necesitan\n  estado_actual: estado\n};\n\nreturn [{ json: output }];"},"type":"n8n-nodes-base.code","typeVersion":2,"position":[1760,2592],"id":"e2c25b83-13c4-4730-bbad-2c6bd224e4fd","name":"Code in JavaScript2"},{"parameters":{"method":"POST","url":"https://lead.integraia.lat/chat-bot-unisa/capturar_lead_http","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Content-Type","value":"application/json"}]},"sendBody":true,"bodyParameters":{"parameters":[{"name":"cedula","value":"={{$json.estado_actual.datos_paciente?.cedula || '''' }}"},{"name":"telefono","value":"={{ $