INSERT INTO public.workflow_entity (name, active, nodes, connections, "createdAt", "updatedAt", settings, "staticData", "pinData", "versionId", "triggerCount", id, meta, "parentFolderId", "isArchived", "versionCounter", description, "activeVersionId") VALUES ('My Sub-Workflow 1', false, '[{"id":"c055762a-8fe7-4141-a639-df2372f30060","typeVersion":1.1,"name":"When Executed by Another Workflow","type":"n8n-nodes-base.executeWorkflowTrigger","position":[260,340],"parameters":{}},{"id":"b5942df6-0160-4ef7-965d-57583acdc8aa","name":"Replace me with your logic","type":"n8n-nodes-base.noOp","position":[520,340],"parameters":{}}]', '{"When Executed by Another Workflow":{"main":[[{"node":"Replace me with your logic","type":"main","index":0}]]}}', '2026-02-07 10:31:57.187+00', '2026-03-03 19:44:12.867+00', '{"executionOrder":"v1","availableInMCP":false}', NULL, '{}', '08b9acdb-71c5-4e88-a3dd-36c5d3596bc7', 0, 'nxriB6aP5aZbwQHy', NULL, NULL, true, 2, NULL, NULL);
INSERT INTO public.workflow_entity (name, active, nodes, connections, "createdAt", "updatedAt", settings, "staticData", "pinData", "versionId", "triggerCount", id, meta, "parentFolderId", "isArchived", "versionCounter", description, "activeVersionId") VALUES ('chatbot_simple_0', false, '[{"parameters":{"public":true,"options":{}},"type":"@n8n/n8n-nodes-langchain.chatTrigger","typeVersion":1.4,"position":[-464,0],"id":"0752b962-0ef5-4574-bd2b-05576890617f","name":"When chat message received","webhookId":"d5fa4d0d-8551-49c4-a934-7ef511557e50"},{"parameters":{"promptType":"define","text":"={{ $json.text }}","options":{"systemMessage":"=¿Sabes cuánto dinero pierdes cada día por no responder rápido en WhatsApp o Instagram?\n\nNo es tu culpa. Nadie puede estar 24/7 pegado al teléfono. Pero cada mensaje sin respuesta es un cliente que se va con otro.\n\nYo te ayudo a recuperar esas ventas. Con una solución completa que trabaja sola, cuesta muy poco y la tienes bajo tu total control.\n\nImagina esto:\nLlega un cliente a tu web a las 11 de la noche preguntando si tienes stock o cuánto cuesta tu servicio. En ese mismo momento, un asistente con IA entrenado con la información de tu negocio le responde al instante. El cliente queda satisfecho, recibe su respuesta y además, si quiere más información, llena un formulario.\n\nAutomáticamente, ese lead entra a tu CRM. Tienes su nombre, teléfono y lo que preguntó. A la mañana siguiente, tú solo te sientas, revisas tu lista de clientes potenciales y empiezas a llamar o enviar mensajes. Todo sin haber movido un dedo en la noche.\n\nY no solo eso: los mensajes que te llegan por WhatsApp, Facebook o Instagram también se guardan solos en ese mismo sistema. Todo en un solo lugar. Todo ordenado. Todo automático.\n\n¿Y si vendes productos?\nEste sistema también puede:\n\nLlevar el control de tu inventario (cuánto te queda, qué se está agotando).\n\nGenerar facturas automáticas cuando vendes.\n\nHacer pedidos a proveedores cuando el stock está bajo.\n\nTener un carrito de compras en tu web.\n\nTodo sin pagar licencias mensuales. Todo sin límites. Todo tuyo.\n\n¿Por qué en tu propia nube y sin cuellos de botella?\nPorque instalamos todo en un servidor privado (VPS) que tú controlas. Nadie más tiene acceso. No dependes de plataformas externas que te limitan o te cobran más cuando creces. Tú eres el dueño absoluto de tus datos y de tu sistema.\n\nY como está en tu propia nube, no hay cuellos de botella: si tu negocio crece, el sistema crece contigo. Sin sorpresas, sin trabas, sin que te digan \"ahora tienes que pagar más porque vendiste más\".\n\n¿Quién soy y por qué puedo ayudarte?\nMe llamo [tu nombre] y llevo más de 20 años resolviendo problemas tecnológicos. He trabajado con Java, Angular, React, bases de datos... He visto de todo. Pero hace unos meses descubrí algo que me apasionó: Odoo Community.\n\n¿Por qué? Porque es un sistema de gestión completo (ventas, inventario, contabilidad, CRM) totalmente gratuito, sin trucos ni letras chiquitas. Y pensé: ¿por qué las pequeñas y medianas empresas no pueden tener lo mismo que las grandes pero sin pagar fortunas?\n\nDesde entonces, me he especializado en implementar Odoo Community para negocios como el tuyo. No soy un vendedor de software. Soy un desarrollador con décadas de experiencia que se sienta contigo, entiende cómo trabajas y adapta el sistema a ti, no al revés.\n\n¿Cuánto cuesta?\nMenos de lo que pagas por un empleado medio día. Y a diferencia de un sueldo, esto trabaja las 24 horas, los 365 días del año, sin descanso, sin pedir aumento, sin irse a la competencia.\n\nEs una inversión única que se paga sola con las primeras ventas que recuperes.\n\nEn resumen, te llevas:\n✅ Una web de dos páginas con IA que responde por ti día y noche.\n✅ Captura automática de leads desde web, WhatsApp, Facebook e Instagram.\n✅ CRM integrado sin costo de licencia.\n✅ Tu propio servidor privado (control total, sin depender de nadie).\n✅ Posibilidad de agregar inventario, facturación, compras y más cuando quieras.\n✅ A mí, con 20 años de experiencia, acompañándote en el proceso.\n\nAsí como yo programé este mensaje para explicarte todo esto en pocos minutos, puedo programar un sistema que haga lo mismo por tu negocio: atender, captar, organizar y vender por ti.\n\n👉 Cuéntame más de tu negocio sin compromiso. Solo necesito 15 minutos para entender cómo trabajas y mostrarte cómo quedaría todo. Déjame tus datos aquí y te contacto: [ENLACE DE CONTACTO]\n\nTu negocio trabajando solo, tú durmiendo tranquilo."}},"type":"@n8n/n8n-nodes-langchain.agent","typeVersion":3.1,"position":[416,0],"id":"0425064b-3fdb-4660-8c74-a09ca3daf310","name":"AI Agent"},{"parameters":{"model":{"__rl":true,"mode":"list","value":"gpt-4.1-mini"},"builtInTools":{},"options":{}},"type":"@n8n/n8n-nodes-langchain.lmChatOpenAi","typeVersion":1.3,"position":[80,208],"id":"7a8b5b94-4ca3-4e94-8047-e92e07be50d9","name":"OpenAI Chat Model","credentials":{"openAiApi":{"id":"SynY9HmZH2SsZkWD","name":"OpenAi account"}}},{"parameters":{},"type":"@n8n/n8n-nodes-langchain.memoryBufferWindow","typeVersion":1.3,"position":[224,208],"id":"63d0e699-476f-49b7-8153-57da2230a0a2","name":"Simple Memory"},{"parameters":{},"type":"n8n-nodes-base.manualTrigger","typeVersion":1,"position":[-464,208],"id":"93cefad9-9050-4e19-bc5f-5197fc841873","name":"When clicking ‘Execute workflow’"},{"parameters":{"assignments":{"assignments":[{"id":"96996d45-ddf6-4f34-850c-6135282de201","name":"text","value":"={{ $json.chatInput }}","type":"string"},{"id":"886653c3-a819-4881-a860-62b44509d731","name":"session_id","value":"={{ $json.sessionId }}","type":"string"},{"id":"ee045dc3-b0e6-4366-b179-2bb78781425b","name":"account_id","value":"","type":"string"},{"id":"4d37a5ee-0b5e-40e0-a5ca-4dc372f0a1e6","name":"conversation_id","value":"","type":"string"},{"id":"3eb0a246-8cb9-477b-a0df-460f3c6b3b8a","name":"message_type","value":"","type":"string"},{"id":"af85fc32-b8b9-43a3-a666-403ad84a8e5f","name":"user_