"type":"string","removed":false},{"id":"agente_desactivado","displayName":"agente_desactivado","required":false,"defaultMatch":false,"display":true,"canBeUsedToMatch":true,"type":"boolean","removed":false}],"attemptToConvertTypes":false,"convertFieldsToString":true},"options":{}},"type":"n8n-nodes-base.executeWorkflow","typeVersion":1.3,"position":[-16,0],"id":"8cd3b42f-4db1-4298-ac9f-4c7567ab2ced","name":"Procesamos_entrada_para_salida_tratada"}]', '{"When chat message received":{"main":[[{"node":"Seteamos_variables","type":"main","index":0}]]},"OpenAI Chat Model":{"ai_languageModel":[[{"node":"AI Agent","type":"ai_languageModel","index":0}]]},"Simple Memory":{"ai_memory":[[{"node":"AI Agent","type":"ai_memory","index":0}]]},"When clicking ‘Execute workflow’":{"main":[[{"node":"Seteamos_variables","type":"main","index":0}]]},"Seteamos_variables":{"main":[[{"node":"Procesamos_entrada_para_salida_tratada","type":"main","index":0}]]},"Procesamos_entrada_para_salida_tratada":{"main":[[{"node":"AI Agent","type":"main","index":0}]]}}', '2026-03-03 21:54:56.161+00', '2026-03-05 20:07:06.514+00', '{"executionOrder":"v1","availableInMCP":false}', NULL, '{"When clicking ‘Execute workflow’":[{"json":{"action":"sendMessage","sessionId":"493f9633-3bb2-403e-96db-b8f75af3cdd0","chatInput":"hola"}}],"AI Agent":[{"json":{"name":"First item","code":1}},{"json":{"name":"Second item","code":2}}]}', '51ba0c37-d2af-4a5e-b2c4-8f820eaa964e', 1, '1qhjqKP6HcajMWeY9WOzU', '{"templateCredsSetupCompleted":true}', '8D5I8uYQ0ZJlE0uO', true, 30, NULL, NULL);
INSERT INTO public.workflow_entity (name, active, nodes, connections, "createdAt", "updatedAt", settings, "staticData", "pinData", "versionId", "triggerCount", id, meta, "parentFolderId", "isArchived", "versionCounter", description, "activeVersionId") VALUES ('tool_citas', false, '[{"parameters":{"promptType":"define","text":"={{ $json.text }}","options":{"systemMessage":"=// =====================================================\n// TÍTULO / REGLA INICIAL\n// =====================================================\n// Eres un agente virtual de UNISA para agendar citas.\n// Tienes dos herramientas disponibles:\n\n// 1️⃣ buscar_por_telefono_http\n//    - Entrada: { telefono }\n//    - Retorna: { cedula, nombre_completo, fecha_nacimiento, telefono, es_paciente_nuevo, existe }\n//    - Regla: Usar SOLO después de que el usuario proporcione un número de WhatsApp válido.\n\n// 2️⃣ capturar_lead_http\n//    - Entrada: Todos los datos del paciente y de la cita.\n//    - Regla: Usar SOLO después de que el usuario confirme el resumen de la cita escribiendo CONFIRMAR.\n\n// =====================================================\n// RESET TOTAL\n// =====================================================\nfunction resetSesion() {\n    paso_actual = \"ESPERANDO_TELEFONO\";\n    contexto = \"TITULAR\"; // TITULAR | FAMILIAR\n\n    paciente = {\n        telefono: \"\",\n        cedula: \"\",\n        nombre_completo: \"\",\n        fecha_nacimiento: \"\",\n        paciente_nuevo: \"\"\n    };\n\n    medio_pago = \"\";\n    servicio = \"\";\n    fecha_cita = \"\";\n    hora_cita = \"\";\n    membresia_interes = \"\";\n    fotos_cedula = [];\n    imagenes_adicionales = [];\n\n    captura_realizada = false;\n    ultima_actividad = Date.now();\n}\n\n// =====================================================\n// INICIALIZACIÓN\n// =====================================================\nif (typeof paso_actual === \"undefined\") {\n    resetSesion();\n}\n\n// =====================================================\n// REINICIO POR INACTIVIDAD (>5 min)\n// =====================================================\nif (Date.now() - ultima_actividad > 5*60*1000) {\n    resetSesion();\n    return \"⏳ Sesión reiniciada. Escribe *agendar cita* para comenzar.\";\n}\nultima_actividad = Date.now();\n\n// =====================================================\n// FUNCIONES AUXILIARES\n// =====================================================\nfunction normalizarTelefono(t) {\n    if (/^0\\d{10}$/.test(t)) return \"+58\" + t.substring(1);\n    if (/^\\+58\\d{10}$/.test(t)) return t;\n    return null;\n}\n\nfunction esUrlValida(u) {\n    return /^https?:\\/\\/\\S+$/.test(u);\n}\n\n// =====================================================\n// PASO 1 – TELÉFONO\n// =====================================================\nif (paso_actual === \"ESPERANDO_TELEFONO\") {\n    let tel = normalizarTelefono(text.trim());\n    if (!tel) return \"📱 Ingresa tu número de WhatsApp con código de país.\\nEjemplo: +584123456789\";\n\n    paciente.telefono = tel;\n    paso_actual = \"BUSCANDO_TELEFONO\";\n\n    // 🔹 Siempre consultar Odoo antes de asumir que no existe\n    return { tool: \"buscar_por_telefono_http\", parameters: { telefono: tel } };\n}\n\n// =====================================================\n// PASO 2 – RESULTADO DE BÚSQUEDA\n// =====================================================\nif (paso_actual === \"BUSCANDO_TELEFONO\" && typeof existe !== \"undefined\") {\n    \n    if (existe === true && nombre_completo && fecha_nacimiento) {\n        paciente.cedula = cedula;\n        paciente.nombre_completo = nombre_completo;\n        paciente.fecha_nacimiento = fecha_nacimiento;\n        paso_actual = \"CONFIRMAR_DATOS\";\n\n        return `✅ Encontramos tus datos:\n\n• Nombre: ${nombre_completo}\n• Cédula: ${cedula}\n• Fecha de nacimiento: ${fecha_nacimiento}\n\n¿Son correctos? (SI / NO)`;\n    }\n\n    // Paciente nuevo o datos incompletos → mantener teléfono y pedir cédula\n    paso_actual = \"REGISTRO_CEDULA\";\n    return \"❌ No encontramos registros completos. Indícame tu cédula para crear un nuevo registro:\";\n}\n\n// =====================================================\n// PASO 3 – CONFIRMAR DATOS EXISTENTES\n// =====================================================\nif (paso_actual === \"CONFIRMAR_DATOS\") {\n    if (/^SI|SÍ$/i.test(text)) {\n        paso_actual = \"MEDIO_PAGO\";\n        return \"¿Pago particular o con seguro médico?\";\n    }\n    if (/^NO$/i.test(text)) {\n        paso_actual = \"REGISTRO_CEDULA\";\n        return \"Perfecto. Indícame tu cédula para actualizar tu registro:\";\n    }\n}\n\n// =====================================================\n// PASO 4 – REGISTRO NUEVO PACIENTE\n// =====================================================\nif (paso_actual === \"REGISTRO_CEDULA\") {\n    paciente.cedula = text.trim();\n    paso_actual = \"REGISTRO_NOMBRE\";\n    return \"Nombre completo:\";\n}\n\nif (paso_actual === \"REGISTRO_NOMBRE\") {\n    paciente.nombre_completo = text.trim();\n    paso_actual = \"REGISTRO_FECHA\";\n    return \"Fecha de nacimiento (dd/mm/aaaa):\";\n}\n\nif (paso_actual === \"REGISTRO_FECHA\") {\n    paciente.fecha_nacimiento = text.trim();\n    paso_actual = \"PACIENTE_NUEVO\";\n    return \"¿Es tu primera vez en UNISA? (SÍ / NO)\";\n}\n\n// 🔹 Nunca pedir WhatsApp de nuevo\nif (paso_actual === \"PACIENTE_NUEVO\") {\n    paciente.paciente_nuevo = text.trim().toUpperCase();\n    paso_actual = \"MEDIO_PAGO\";\n    return \"¿Pago particular o con seguro médico?\";\n}\n\n// =====================================================\n// PASO 5 – DATOS DE LA CITA\n// =====================================================\nif (paso_actual === \"MEDIO_PAGO\") {\n    medio_pago = text.trim();\n    paso_actual = \"SERVICIO\";\n    return \"¿Qué servicio necesitas?\";\n}\n\nif (paso_actual === \"SERVICIO\") {\n    servicio = text.trim();\n    paso_actual = \"FECHA_CITA\";\n    return \"¿Para qué fecha deseas la cita? (dd/mm/aaaa)\";\n}\n\nif (paso_actual === \"FECHA_CITA\") {\n    fecha_cita = text.trim();\n    paso_actual = \"HORA_CITA\";\n    return \"¿Prefieres horario de mañana o tarde?\";\n}\n\nif (paso_actual === \"HORA_CITA\") {\n    hora_cita = text.trim().toUpperCase();\n    paso_actual = \"MEMBRESIA\";\n    return \"¿Te interesa la membresía? (SÍ / NO)\";\n}\n\nif (paso_actual === \"MEMBRESIA\") {\n    membresia_interes = text.trim().toUpperCase();\n    paso_actual = \"FOTOS_CEDULA\";\n    return \"📸 Por favor, envía la foto de tu cédula (URLs separadas por comas) o escribe *SALTAR* si no deseas enviar.\";\n}\n\n// =====================================================\n// PASO 6 – FOTOS DE CÉDULA\n// =====================================================\nif (paso_actual === \"FOTOS_CEDULA\") {\n    if (text.toUpperCase() !== \"SALTAR\") {\n        fotos_cedula = text.split(\",\").map(u => u.trim()).filter(esUrlValida);\n    }\n    paso_actual = \"IMAGENES_ADICIONALES\";\n    return \"Si deseas, envía imágenes adicionales (URLs separadas por comas) o escribe *SALTAR*.\";\n}\n\n// =====================================================\n// PASO 7 – IMÁGENES ADICIONALES\n// =====================================================\nif (paso_actual === \"IMAGENES_ADICIONALES\") {\n    if (text.toUpperCase() !== \"SALTAR\") {\n        imagenes_adicionales = text.split(\",\").map(u => u.trim()).filter(esUrlValida);\n    }\n    paso_actual = \"RESUMEN\";\n}\n\n// =====================================================\n// PASO 8 – RESUMEN\n// =====================================================\nif (paso_actual === \"RESUMEN\") {\n    paso_actual = \"ESPERANDO_CONFIRMACION\";\n\n    return `🩺 **RESUMEN DE TU CITA**\n\n• Nombre: ${paciente.nombre_completo}\n• Cédula: ${paciente.cedula}\n• Teléfono: ${paciente.telefono}\n• Servicio: ${servicio}\n• Fecha: ${fecha_cita}\n• Hora: ${hora_cita}\n• Pago: ${medio_pago}\n• Fotos cédula: ${fotos_cedula.length ? fotos_cedula.join(\", \") : \"No enviadas\"}\n• Imágenes adicionales: ${imagenes_adicionales.length ? imagenes_adicionales.join(\", \") : \"No enviadas\"}\n\nEscribe *CONFIRMAR* para finalizar.`;\n}\n\n// =====================================================\n// PASO 9 – CONFIRMAR Y CAPTURAR\n// =====================================================\nif (paso_actual === \"ESPERANDO_CONFIRMACION\" && text.toUpperCase() === \"CONFIRMAR\" && !captura_realizada) {\n    captura_realizada = true;\n    paso_actual = \"FINALIZADO\";\n\n    return {\n        tool: \"capturar_lead_http\",\n        parameters: {\n            ...paciente,\n            medio_pago,\n            servicio,\n            fecha_preferida: fecha_cita,\n            hora_preferida: hora_cita,\n            membresia_interes,\n            fotos_cedula,\n            imagenes_adicionales,\n            plataforma: \"whatsapp\"\n        }\n    };\n}\n\n// =====================================================\n// PASO 10 – FINAL\n// =====================================================\nif (paso_actual === \"FINALIZADO\") {\n    return \"✅ **CITA REGISTRADA CORRECTAMENTE**\\n\\n¿Deseas agendar otra cita para un familiar?\";\n}\n\nreturn \"Por favor continúa paso a paso.\";\n"}},"type":"@n8n/n8n-nodes-langchain.agent","typeVersion":2.2,"position":[2944,32],"id":"96ef5469-6341-47e2-ae6b-8ab603d4394f","name":"AI_gent_Citas"},{"parameters":{"model":{"__rl":true,"mode":"list","value":"gpt-4o-mini"},"options":{}},"type":"@n8n/n8n-nodes-langchain.lmChatOpenAi","typeVersion":1.2,"position":[2800,336],"id":"852829c1-6381-46eb-b1b9-f1c0cdd7efb9","name":"OpenAI Chat Model","credentials":{"openAiApi":{"id":"SynY9HmZH2SsZkWD","name":"OpenAi account"}}},{"parameters":{"sessionIdType":"customKey","sessionKey":"={{ $json.session_id }}","contextWindowLength":15},"type":"@n8n/n8n-nodes-langchain.memoryBufferWindow","typeVersion":1.3,"position":[2992,336],"id":"d52dc086-1fd9-42ed-8539-917e5b90abbd","name":"Simple Memory"},{"parameters":{"inputSource":"jsonExample","jsonExample":"{\n \"text\": \"quiero una cita\",\n \"session_id\": \"123\",\n \"platform\": \"whatsapp\",\n\"image_url\":\"image_url\"\n}"},"type":"n8n-nodes-base.executeWorkflowTrigger","typeVersion":1.1,"position":[2512,32],"id":"4d68e92c-6af0-402e-809b-3147c0a430ea","name":"tool_citas"},{"parameters":{"toolDescription":"Busca un paciente en el sistema UNISA usando su número de teléfono. Devuelve datos como cedula, nombre_completo, fecha_nacimiento, telefono, es_paciente_nuevo y existe.","method":"POST","url":"https://jumpjibe.com/chat-bot-unisa/buscar_por_telefono_http","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Content-Type","value":"application/json"},{}]},"sendBody":true,"bodyParameters":{"parameters":[{"name":"telefono","value":"={{ $fromAI(''telefono'', '''', ''string'') }}"}]},"options":{}},"type":"n8n-nodes-base.httpRequestTool","typeVersion":4.2,"position":[3200,304],"id":"b5d61d8b-f2e0-4b08-9ace-ce1f46a1cb82","name":"buscar_por_telefono_http"},{"parameters":{"toolDescription":"Registra un lead/cita en Odoo con todos los datos del paciente. Úsala solo cuando el usuario confirme todo.","method":"POST","url":"https://jumpjibe.com/chat-bot-unisa/capturar_lead_http","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Content-Type","value":"application/json"}]},"sendBody":true,"bodyParameters":{"parameters":[{"name":"cedula","value":"={{ $fromAI(''cedula'', '''', ''string'') }}"},{"name":"telefono","value":"={{ $fromAI(''telefono'', '''', ''string'') }}"},{"name":"nombre_completo","value":"={{ $fromAI(''nombre_completo'', '''', ''string'') }}"},{"name":"fecha_nacimiento","value":"={{ $fromAI(''fecha_nacimiento'', '''', ''string'') }}"},{"name":"plataforma","value":"={{ $json.platform }}"},{"name":"fecha_preferida","value":"={{ $fromAI(''fecha_deseada'', '''', ''string'') }}"},{"name":"hora_preferida","value":"={{ $fromAI(''hora_preferida'', '''', ''string'') }}"},{"name":"servicio","value":"={{ $fromAI(''servicio'', '''', ''string'') }}"},{"name":"medio_pago","value":"={{ $fromAI(''medio_pago'', '''', ''string'') }}"},{"name":"paciente_nuevo","value":"={{ $fromAI(''paciente_nuevo'', '''', ''string'') }}"},{"name":"membresia_interes","value":"={{ $fromAI(''membresia_interes'', '''', ''string'') }}"},{"name":"foto_cedula_url","value":"={{ $fromAI(''foto_cedula_url'', '''', ''string'') }}"},{"name":"imagenes_adicionales","value":"={{ $fromAI(''imagenes_adicionales'', '''', ''string'') }}"}]},"options":{"timeout":30000}},"type":"n8n-nodes-base.httpRequestTool","typeVersion":4.2,"position":[3344,272],"id":"82072694-6940-42aa-9fe7-9c64366d4358","name":"capturar_lead_http"},{"parameters":{"jsCode":"for (const item of $input.all()) {\n  console.log(\"=== DEBUG Verificar_imagen_texto ===\");\n  console.log(\"Texto original:\", item.json.text);\n  console.log(\"image_url original:\", item.json.image_url);\n\n  // **NUEVO: SIEMPRE PASAR current_image_url INCLUSO CUANDO NO HAY IMAGEN**\n  if (item.json.image_url && item.json.image_url.includes(\"http\")) {\n    item.json.text = \"IMAGEN_ENVIADA\";\n    item.json.current_image_url = item.json.image_url;\n    console.log(\"✅ IMAGEN DETECTADA - URL expuesta en current_image_url:\", item.json.current_image_url);\n  } else {\n    if (item.json.text && item.json.text.toLowerCase().trim() === \"saltar\") {\n      item.json.text = \"SALTAR\";\n    }\n    // **NUEVO: SIEMPRE PONER current_image_url AUNQUE SEA VACÍO**\n    item.json.current_image_url = \"\";\n  }\n\n  // **NUEVO: AGREGAR VARIABLES DE VERIFICACIÓN**\n  item.json.debug_image_url = item.json.image_url || \"NO_IMAGE\";\n  item.json.debug_current_url = item.json.current_image_url || \"NO_CURRENT_URL\";\n  \n  console.log(\"Texto final enviado al agente:\", item.json.text);\n  console.log(\"current_image_url final:\", item.json.current_image_url || \"vacío\");\n  console.log(\"debug_image_url:\", item.json.debug_image_url);\n  console.log(\"debug_current_url:\", item.json.debug_current_url);\n  console.log(\"=== FIN DEBUG ===\");\n}\n\nreturn $input.all();"},"type":"n8n-nodes-base.code","typeVersion":2,"position":[2704,32],"id":"57d9acec-402a-44ac-84f9-2b2f74d62cfc","name":"Verificar_imagen_texto"}]', '{"OpenAI Chat Model":{"ai_languageModel":[[{"node":"AI_gent_Citas","type":"ai_languageModel","index":0}]]},"Simple Memory":{"ai_memory":[[{"node":"AI_gent_Citas","type":"ai_memory","index":0}]]},"tool_citas":{"main":[[{"node":"Verificar_imagen_texto","type":"main","index":0}]]},"buscar_por_telefono_http":{"ai_tool":[[{"node":"AI_gent_Citas","type":"ai_tool","index":0}]]},"capturar_lead_http":{"ai_tool":[[{"node":"AI_gent_Citas","type":"ai_tool","index":0}]]},"Verificar_imagen_texto":{"main":[[{"node":"AI_gent_Citas","type":"main","index":0}]]}}', '2026-01-11 13:16:11.216+00', '2026-03-03 19:44:38.112+00', '{"executionOrder":"v1"}', NULL, '{}', '96321642-b26b-4cc5-a5e9-bbcf13867886', 0, 'a1CIiSg66iwrhRNH', NULL, NULL, true, 18, NULL, NULL);
INSERT INTO public.workflow_entity (name, active, nodes, connections, "createdAt", "updatedAt", settings, "staticData", "pinData", "versionId", "triggerCount", id, meta, "parentFolderId", "isArchived", "versionCounter", description, "activeVersionId") VALUES ('canaliza_ws-ig-fb-tg_odoo_1', true, '[{"parameters":{"resource":"audio","operation":"transcribe","options":{}},"type":"@n8n/n8n-nodes-langchain.openAi","typeVersion":1.8,"position":[-1312,544],"id":"cb10fbf2-bcc9-4742-bddd-e6c9bcbce89c","name":"Audio_a_Texto_whatsapp","credentials":{"openAiApi":{"id":"SynY9HmZH2SsZkWD","name":"OpenAi account"}}},{"parameters":{"url":"={{ $json.image_url }}","authentication":"genericCredentialType","genericAuthType":"httpBearerAuth","sendHeaders":true,"headerParameters":{"parameters":[{}]},"options":{}},"type":"n8n-nodes-base.httpRequest","typeVersion":4.2,"position":[-1488,544],"id":"697f23fc-7707-48f7-841f-298cbd0e7292","name":"Get File Data","alwaysOutputData":true,"credentials":{"httpBearerAuth":{"id":"SxSs5ggMU2LgbDMZ","name":"Bearer Auth account"}}},{"parameters":{"assignments":{"assignments":[{"id":"f85334e7-e910-4938-8c4b-4555f55c7ba0","name":"text","value":"={{ $json.text || ''0''}}","type":"string"},{"id":"a1b2c3d4-e5f6-7890-abcd-ef1234567890","name":"session_id","value":"={{ $json.session_id }}","type":"string"},{"id":"image_url_passed","name":"image_url","value":"={{ $json.image_url || '''' }}","type":"string"},{"id":"1af7f04d-4a46-4b3d-930a-4cf8dcd2314e","name":"platform","value":"={{ $json.platform }}","type":"string"},{"id":"d6f22467-af6c-493b-a7b3-54389897f457","name":"account_id","value":"={{ $json.account_id }}","type":"string"},{"id":"a49a0e8c-4a5c-4e96-a135-dec725ea4440","name":"conversation_id","value":"={{ $json.conversation_id }}","type":"string"},{"id":"700afea9-14f5-4411-a461-4ff98e82641a","name":"platform","value":"={{ $json.platform }}","type":"string"},{"id":"4c7a2d7e-bf8d-4ee1-ae36-0d2f66ab9de0","name":"message_type","value":"{{$json.message_type}}"