put.all()[0]?.json || {};\n\n// 2. Obtener datos de Consultar_estado_Odoo (segundo elemento del merge)\n// La respuesta de Odoo viene como array: [{...}]\nlet datosOdoo = $input.all()[1]?.json;\nif (Array.isArray(datosOdoo) && datosOdoo.length > 0) {\n    datosOdoo = datosOdoo[0];\n} else {\n    datosOdoo = datosOdoo || {};\n}\n\nconsole.log(\"📥 DATOS DE ODOO (crudo):\", JSON.stringify($input.all()[1]?.json, null, 2));\nconsole.log(\"📥 DATOS DE ODOO (procesado):\", JSON.stringify(datosOdoo, null, 2));\n\n// 3. Extraer el estado_anterior - AHORA SE LLAMA \"estado\" en lugar de \"debug_estado_nuevo\"\nconst estado_anterior = datosOdoo.estado || null;\nconst modoOdoo = estado_anterior?.modo || datosOdoo.modo || null;\nconst pasoOdoo = estado_anterior?.paso || datosOdoo.paso || null;\nconst tipo_dato = estado_anterior?.tipo_dato || datosOdoo.tipo_dato || null\nconst es_requerido = estado_anterior?.es_requerido || datosOdoo.es_requerido || null\nconst mensaje_prompt = estado_anterior?.mensaje_prompt || datosOdoo.mensaje_prompt || null\nconst nombre_mostrar = estado_anterior?.nombre_mostrar || datosOdoo.nombre_mostrar || null\n\n\n\n// 4. Crear el resultado en el formato EXACTO solicitado\nconst resultadoFinal = {\n    // Campos de Preparar_Input_AI\n    text: datosPrepararInput.text || \"0\",\n    session_id: datosPrepararInput.session_id || \"\",\n    image_url: datosPrepararInput.image_url || \"\",\n    platform: datosPrepararInput.platform || \"whatsapp\",\n    account_id: datosPrepararInput.account_id || \"\",\n    conversation_id: datosPrepararInput.conversation_id || \"\",\n    \n    // Campos de Odoo (estado_anterior completo)\n    estado_anterior: estado_anterior,\n    \n    // Campos adicionales de Odoo (modo y paso al nivel raíz también)\n    modo: modoOdoo,\n    paso: pasoOdoo,\n\n    tipo_dato: tipo_dato,\n    es_requerido: es_requerido,\n    mensaje_prompt: mensaje_prompt,\n    nombre_mostrar: nombre_mostrar,\n    // Datos paciente para fácil acceso\n    datos_paciente: estado_anterior?.datos_paciente || {}\n};\n\n// 5. Si estado_anterior es null, crear estructura básica\nif (!estado_anterior) {\n    resultadoFinal.estado_anterior = {\n        modo: datosOdoo.modo || null,\n        paso: datosOdoo.paso || null,\n        datos_paciente: {},\n        timestamp: null\n    };\n}\n\nconsole.log(\"✅ RESULTADO FINAL:\");\nconsole.log(JSON.stringify(resultadoFinal, null, 2));\n\nreturn [{ json: resultadoFinal }];"},"type":"n8n-nodes-base.code","typeVersion":2,"position":[832,720],"id":"5a8b69c0-ec3b-458d-a54c-9c13c2752e39","name":"Recuperar_paso"},{"parameters":{"url":"={{ $json.image_url }}","authentication":"genericCredentialType","genericAuthType":"httpBearerAuth","sendHeaders":true,"headerParameters":{"parameters":[{}]},"options":{}},"type":"n8n-nodes-base.httpRequest","typeVersion":4.2,"position":[-1488,544],"id":"c037859d-1a11-48c7-bbf2-f74919721ba0","name":"Obtenemos_imagen","alwaysOutputData":true,"credentials":{"httpBearerAuth":{"id":"SxSs5ggMU2LgbDMZ","name":"Bearer Auth account"}}}]', '{"Audio_a_Texto_whatsapp":{"main":[[{"node":"Extraer_Texto_Audio","type":"main","index":0}]]},"Texto_o_Audio?":{"main":[[{"node":"Obtener_Info","type":"main","index":0}],[{"node":"Obtenemos_imagen","type":"main","index":0}],[{"node":"Procesar_Imagen_whatsapp","type":"main","index":0}]]},"Procesar_Imagen_whatsapp":{"main":[[{"node":"Preparar_Input_AI","type":"main","index":0}]]},"Extraer_Texto_Audio":{"main":[[{"node":"Merge","type":"main","index":1}]]},"Preparar_Input_AI":{"main":[[{"node":"Consultar_estado_Odoo","type":"main","index":0},{"node":"Combinar_entrada_session_odoo","type":"main","index":0}]]},"Buffer":{"main":[[{"node":"Wait","type":"main","index":0}]]},"Wait":{"main":[[{"node":"Get_buffer_data","type":"main","index":0}]]},"Get_buffer_data":{"main":[[{"node":"If","type":"main","index":0}]]},"If":{"main":[[{"node":"Agrupar_texto_acumulado_resto_variables_enviar","type":"main","index":0}],[{"node":"No Operation, do nothing",