a59-4aaf-b820-30d26c5cb334","name":"Code in JavaScript"}]', '{"answer-chastwoot-whatsapp":{"main":[[{"node":"Texto_o_Audio?","type":"main","index":0}]]},"Audio_a_Texto_whatsapp":{"main":[[{"node":"Extraer_Texto_Audio","type":"main","index":0}]]},"Get File Data":{"main":[[{"node":"Audio_a_Texto_whatsapp","type":"main","index":0}]]},"Texto_o_Audio?":{"main":[[{"node":"Obtener_Info","type":"main","index":0}],[{"node":"Get File Data","type":"main","index":0},{"node":"Merge","type":"main","index":1}],[{"node":"Procesar_Imagen_whatsapp","type":"main","index":0}]]},"Procesar_Imagen_whatsapp":{"main":[[{"node":"Preparar_Input_AI","type":"main","index":0}]]},"Extraer_Texto_Audio":{"main":[[{"node":"Merge","type":"main","index":0}]]},"Obtener_Info":{"main":[[{"node":"Preparar_Input_AI","type":"main","index":0}]]},"When clicking ‘Execute workflow’":{"main":[[]]},"Merge":{"main":[[{"node":"Code in JavaScript","type":"main","index":0}]]},"Code in JavaScript":{"main":[[{"node":"Preparar_Input_AI","type":"main","index":0}]]}}', '2026-02-07 10:24:06.244+00', '2026-02-12 21:12:10.195+00', '{"executionOrder":"v1","availableInMCP":false}', NULL, '{"When clicking ‘Execute workflow’":[{"json":{"session_id":"584142711347","platform":"whatsapp","image_url":"https://chatwoot.jumpjibe.com/rails/active_storage/blobs/redirect/eyJfcmFpbHMiOnsibWVzc2FnZSI6IkJBaHBBb3dCIiwiZXhwIjpudWxsLCJwdXIiOiJibG9iX2lkIn19--076d22c31c7e3e0fd7a9c5a52dc444a607ce2a7b/File.ogg","account_id":"1","conversation_id":"7","file_type":"audio"}}]}', '137e65e5-39b4-44e3-aceb-65bf8183b66b', 0, 'ueglPNDbw5ZZWMvkZxvUB', NULL, 'U9r95Q5njBlyLM0X', false, 50, NULL, 'fdeea54d-b901-43ac-b3a8-16d8fc950202');
INSERT INTO public.workflow_entity (name, active, nodes, connections, "createdAt", "updatedAt", settings, "staticData", "pinData", "versionId", "triggerCount", id, meta, "parentFolderId", "isArchived", "versionCounter", description, "activeVersionId") VALUES ('tool_citas', true, '[{"parameters":{"promptType":"define","text":"={{ $json.text }}","options":{"systemMessage":"={\n  \"en_flujo_citas\": true\n}\n\n🩺 FLUJO DE CITAS UNISA — VERSIÓN CORREGIDA Y ESTABLE\n🔐 REGLAS GLOBALES\n\n\n\nSi un dato ya existe → NO se vuelve a pedir\n\nLas imágenes SIEMPRE se capturan desde current_image_url\n\nNunca usar el texto \"IMAGEN_ENVIADA\" como valor\n\nPASO 1 — INICIO\n📱 Para comenzar, necesito tu WhatsApp con código de país.\nEjemplo: +584123456789\n\n\n→ telefono_busqueda\n\nPASO 2 — BÚSQUEDA DE PACIENTE\n\nEjecutar: buscar_por_telefono_http\n\nSI ENCUENTRA PACIENTE:\n\nGuardar automáticamente:\n\nnombre_completo\n\ncedula\n\ntelefono\n\nResponder:\n\n✅ INFORMACIÓN ENCONTRADA\n\n👤 Datos del paciente:\n• Nombre: {{nombre_completo}}\n• Cédula: {{cedula}}\n• Teléfono: {{telefono}}\n\n¿Pago particular o con seguro médico?\n\n\n→ medio_pago\n\nSI NO ENCUENTRA PACIENTE:\n🆕 No encontramos registro previo.\n¿Pago particular o con seguro médico?\n\n\n→ medio_pago\n\nPASO 3 — CÉDULA (CON VALIDACIÓN REAL)\n🔹 SI cedula YA EXISTE:\n✅ Ya tenemos tu cédula registrada: {{cedula}}\nContinuemos.\n\n\n→ NO pedir cédula\n→ Ir a FOTO DE CÉDULA\n\n🔹 SI cedula NO EXISTE:\nPor favor, indícame tu número de cédula (solo números):\n\n\n→ cedula\n\nPASO 4 — FOTO DE CÉDULA (OBLIGATORIO VERIFICAR)\n📷 Envíame una foto clara de tu cédula (frente) o escribe SALTAR.\n\nSI text = \"IMAGEN_ENVIADA\":\n\nUsar current_image_url\n\nfoto_cedula_url = current_image_url\n\n\nValidar:\n\nempieza con https:// → ✅ continuar\n\nno válida → ❌ pedir de nuevo\n\nResponder:\n\n✅ Foto de cédula recibida correctamente.\n\nSI usuario escribe \"SALTAR\":\nContinuemos sin foto de cédula.\n\nSI otro texto:\n⚠️ Envía la foto de tu cédula o escribe SALTAR.\n\nPASO 5 — NOMBRE (CON VALIDACIÓN)\nSI nombre_completo YA EXISTE:\n✅ Nombre registrado: {{nombre_completo}}\n\n\n→ Continuar\n\nSI NO EXISTE:\nPor favor, indícame tu nombre completo:\n\n\n→ nombre_completo\n\nPASO 6 — DATOS PERSONALES\nFecha de nacimiento (dd/mm/aaaa):\n\n\n→ fecha_nacimiento\n\n¿Primera vez en UNISA? (SÍ/NO)\n\n\n→ paciente_nuevo\n\n¿Qué servicio necesitas?\n\n\n→ servicio\n\n¿Para cuándo? (Lo antes posible / Esta semana / Próxima semana)\n\n\n→ fecha_deseada\n\n¿Prefieres horario de mañana o tarde?\n\n\n→ hora_preferida\n\n¿Te interesa nuestro programa de membresía? (SÍ/NO)\n\n\n→ membresia_interes\n\nPASO 7 — DOCUMENTOS ADICIONALES (CON ACUMULACIÓN)\n¿Tienes órdenes médicas para compartir?\nEnvía las imágenes o escribe NO.\n\nSI IMAGEN:\nimagenes_adicionales =\nimagenes_adicionales\n  ? imagenes_adicionales + \",\" + current_image_url\n  : current_image_url\n\n✅ Documento recibido. ¿Más imágenes o NO?\n\nSI \"NO\":\nContinuemos.\n\nPASO 8 — VERIFICACIÓN FINAL (INTERNA)\nfunction verificarImagen(valor) {\n  if (!valor) return \"VACÍO\";\n  if (valor.includes(\"IMAGEN\")) return \"ERROR\";\n  if (valor.startsWith(\"https://\")) return \"OK\";\n  return \"ERROR\";\n}\n\n\n❌ Si hay ERROR → pedir imagen nuevamente\n✅ Si todo OK → continuar\n\nPASO 9 — RESUMEN FINAL\n📋 RESUMEN DE TU CITA:\n\n• Nombre: {{nombre_completo}}\n• Teléfono: {{telefono}}\n• Cédula: {{cedula}}\n• Foto de cédula: {{foto_cedula_url ? \"✅ CAPTURADA\" : \"❌ NO\"}}\n• Servicio: {{servicio}}\n• Fecha deseada: {{fecha_deseada}}\n• Horario: {{hora_preferida}}\n• Medio de pago: {{medio_pago}}\n• Paciente nuevo: {{paciente_nuevo}}\n• Membresía: {{membresia_interes}}\n• Órdenes médicas: {{imagenes_adicionales ? \"✅ CAPTURADAS\" : \"❌ NO\"}}\n\n¿Confirmas para agendar?  \nCONFIRMAR / CANCELAR\n\nPASO 10 — CIERRE\n\n{\n  \"en_flujo_citas\": false\n}\n\n\nCONFIRMAR → capturar_lead_http\n\nCANCELAR → ❌ Cita cancelada\n"}},"type":"@n8n/n8n-nodes-langchain.agent","typeVersion":2.2,"position":[2272,560],"id":"cb5437cd-2daf-4c2a-a568-85d1975a9c23","name":"AI_gent_Citas"},{"parameters":{"model":{"__rl":true,"mode":"list","value":"gpt-4o-mini"},"options":{}},"type":"@n8n/n8n-nodes-langchain.lmChatOpenAi","typeVersion":1.2,"position":[2128,864],"id":"a0c804c9-3092-4443-b8e7-f4655e757298","name":"OpenAI Chat Model","credentials":{"openAiApi":{"id":"SynY9HmZH2SsZkWD","name":"OpenAi account"}}},{"parameters":{"sessionIdType":"customKey","sessionKey":"={{ $json.session_id }}","contextWindowLength":15},"type":"@n8n/n8n-nodes-langchain.memoryBufferWindow","typeVersion":1.3,"position":[2320,864],"id":"b0d19294-727a-49f8-91bd-79b1e8ee3f39","name":"Simple Memory","disabled":true},{"parameters":{"inputSource":"jsonExample","jsonExample":"{\n \"text\": \"quiero una cita\",\n \"session_id\": \"123\",\n \"platform\": \"whatsapp\",\n\"image_url\":\"image_url\"\n}"},"type":"n8n-nodes-base.executeWorkflowTrigger","typeVersion":1.1,"position":[1840,560],"id":"202028c2-0667-4dd0-a066-d32d08c6ec98","name":"tool_citas"},{"parameters":{"toolDescription":"Busca un paciente en el sistema UNISA usando su número de teléfono. Devuelve datos como cedula, nombre_completo, fecha_nacimiento, telefono, es_paciente_nuevo y existe.","method":"POST","url":"https://jumpjibe.com/chat-bot-unisa/buscar_por_telefono_http","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Content-Type","value":"application/json"}]},"sendBody":true,"bodyParameters":{"parameters":[{"name":"telefono","value":"={{ $fromAI(''telefono'', '''', ''string'') }}"}]},"options":{}},"type":"n8n-nodes-base.httpRequestTool","typeVersion":4.2,"position":[2528,832],"id":"9b66bd34-be7f-4906-a2da-652aaa25737d","name":"buscar_por_telefono_http"},{"parameters":{"toolDescription":"Registra un lead/cita en Odoo con todos los datos del paciente. Úsala solo cuando el usuario confirme todo.","method":"POST","url":"https://jumpjibe.com/chat-bot-unisa/capturar_lead_http","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Content-Type","value":"application/json"}]},"sendBody":true,"bodyParameters":{"parameters":[{"name":"cedula","value":"={{ $fromAI(''cedula'', '''', ''string'') }}"},{"name":"telefono","value":"={{ $fromAI(''telefono'', '''', ''string'') }}"},{"name":"nombre_completo","value":"={{ $fromAI(''nombre_completo'', '''', ''string'') }}"},{"name":"fecha_nacimiento","value":"={{ $fromAI(''fecha_nacimiento'', '''', ''string'') }}"},{"name":"plataforma","value":"={{ $json.platform }}"},{"name":"fecha_preferida","value":"={{ $fromAI(''fecha_deseada'', '''', ''string'') }}"},{"name":"hora_preferida","value":"={{ $fromAI(''hora_preferida'', '''', ''string'') }}"},{"name":"servicio","value":"={{ $fromAI(''servicio'', '''', ''string'') }}"},{"name":"medio_pago","value":"={{ $fromAI(''medio_pago'', '''', ''string'') }}"},{"name":"paciente_nuevo","value":"={{ $fromAI(''paciente_nuevo'', '''', ''string'') }}"},{"name":"membresia_interes","value":"={{ $fromAI(''membresia_interes'', '''', ''string'') }}"},{"name":"foto_cedula_url","value":"={{ $fromAI(''foto_cedula_url'', '''', ''string'') }}"},{"name":"imagenes_adicionales","value":"={{ $fromAI(''imagenes_adicionales'', '''', ''string'') }}"}]},"options":{"timeout":30000}},"type":"n8n-nodes-base.httpRequestTool","typeVersion":4.2,"position":[2672,800],"id":"a8d30737-5ed2-478e-9d2d-924ae4c76d94","name":"capturar_lead_http"},{"parameters":{"jsCode":"for (const item of $input.all()) {\n  console.log(\"=== DEBUG Verificar_imagen_texto ===\");\n  console.log(\"Texto original:\", item.json.text);\n  console.log(\"image_url original:\", item.json.image_url);\n  console.log(\"session_id original:\", item.json.session_id);\n\n  // **NUEVO: SIEMPRE PASAR current_image_url INCLUSO CUANDO NO HAY IMAGEN**\n  if (item.json.image_url && item.json.image_url.includes(\"http\")) {\n    item.json.text = \"IMAGEN_ENVIADA\";\n    item.json.current_image_url = item.json.image_url;\n    console.log(\"✅ IMAGEN DETECTADA - URL expuesta en current_image_url:\", item.json.current_image_url);\n  } else {\n    if (item.json.text && item.json.text.toLowerCase().trim() === \"saltar\") {\n      item.json.text = \"SALTAR\";\n    }\n    // **NUEVO: SIEMPRE PONER current_image_url AUNQUE SEA VACÍO**\n    item.json.current_image_url = \"\";\n  }\n\n  // **NUEVO: AGREGAR VARIABLES DE VERIFICACIÓN**\n  item.json.debug_image_url = item.json.image_url || \"NO_IMAGE\";\n  item.json.debug_current_url = item.json.current_image_url || \"NO_CURRENT_URL\";\n  \n  // **NUEVO: AGREGAR sessionId (alias de session_id para consistencia)**\n  item.json.sessionId = item.json.session_id || \"\";\n  \n  console.log(\"Texto final enviado al agente:\", item.json.text);\n  console.log(\"current_image_url final:\", item.json.current_image_url || \"vacío\");\n  console.log(\"debug_image_url:\", item.json.debug_image_url);\n  console.log(\"debug_current_url:\", item.json.debug_current_url);\n  console.log(\"sessionId (nuevo campo):\", item.json.sessionId);\n  console.log(\"=== FIN DEBUG ===\");\n}\n\nreturn $input.all();"},"type":"n8n-nodes-base.code","typeVersion":2,"position":[2032,560],"id":"5525acf6-3e33-4e4b-8037-40edce7df394","name":"Verificar_imagen_texto"},{"parameters":{},"type":"n8n-nodes-base.manualTrigger","typeVersion":1,"position":[1888,816],"id":"a2b003e9-8aee-47d7-816e-d30e7b729f22","name":"When clicking ‘Execute workflow’"},{"parameters":{},"type":"n8n-nodes-base.merge","typeVersion":3.2,"position":[2592,464],"id":"663aae81-b9f3-41ed-bddb-433fc32532df","name":"Merge","disabled":true},{"parameters":{"jsCode":"// Primero, veamos qué estructura tiene realmente la entrada\nconst inputData = $input.all();\nconsole.log(''=== DEBUG INPUT STRUCTURE ==='');\nconsole.log(''Número de items:'', inputData.length);\nconsole.log(''inputData:'', JSON.stringify(inputData, null, 2));\n\nfor (let i = 0; i < inputData.length; i++) {\n  console.log(`\\nItem ${i}:`);\n  console.log(''Tipo:'', typeof inputData[i]);\n  console.log(''Contenido:'', JSON.stringify(inputData[i], null, 2));\n  \n  if (inputData[i].json) {\n    console.log(`Item ${i} tiene propiedad ''json'':`, Array.isArray(inputData[i].json) ? ''ES ARRAY'' : ''NO ES ARRAY'');\n  }\n}\n\n// Ahora procesemos según lo que veamos\nlet jsonArray;\n\nif (inputData.length === 1 && inputData[0].json && Array.isArray(inputData[0].json)) {\n  // Caso: un solo item con propiedad json que es array\n  jsonArray = inputData[0].json;\n  console.log(''Usando inputData[0].json como array'');\n} else if (inputData.length > 1) {\n  // Caso: múltiples items, cada uno es un objeto del array\n  jsonArray = inputData.map(item => item.json || item);\n  console.log(''Combinando múltiples items en array'');\n} else {\n  // Otros casos\n  jsonArray = inputData[0].json || inputData[0];\n  if (!Array.isArray(jsonArray)) {\n    jsonArray = [jsonArray];\n  }\n}\n\nconsole.log(''\\n=== JSON ARRAY PARA PROCESAR ==='');\nconsole.log(''Longitud:'', jsonArray.length);\nconsole.log(''Contenido:'', JSON.stringify(jsonArray, null, 2));\n\n// Procesar como antes\nif (jsonArray.length >= 2) {\n  const mainObject = jsonArray[0];\n  const outputObj = jsonArray.find(item => item && item.output);\n  \n  if (outputObj && outputObj.output) {\n    mainObject.text = outputObj.output;\n    mainObject.output = outputObj.output;\n  }\n  \n  return [mainObject];\n} else if (jsonArray.length === 1 && jsonArray[0].output) {\n  // Si solo tenemos el objeto con output\n  return [{ text: jsonArray[0].output }];\n} else {\n  return [{}];\n}"},"type":"n8n-nodes-base.code","typeVersion":2,"position":[2800,464],"id":"faa55e54-7192-46d9-81c8-c502c8b87971","name":"Code in JavaScript","disabled":true},{"parameters":{"contextWindowLength":10},"type":"@n8n/n8n-nodes-langchain.memoryPostgresChat","typeVersion":1.3,"position":[2288,768],"id":"80a37459-a748-4326-88cd-7b93db13623f","name":"Postgres Chat Memory","credentials":{"postgres":{"id":"ipI4deAzxTgkZ7qT","name":"Postgres account"}}}]', '{"OpenAI Chat Model":{"ai_languageModel":[[{"node":"AI_gent_Citas","type":"ai_languageModel","index":0}]]},"Simple Memory":{"ai_memory":[[]]},"tool_citas":{"main":[[{"node":"Verificar_imagen_texto","type":"main","index":0}]]},"buscar_por_telefono_http":{"ai_tool":[[{"node":"AI_gent_Citas","type":"ai_tool","index":0}]]},"capturar_lead_http":{"ai_tool":[[{"node":"AI_gent_Citas","type":"ai_tool","index":0}]]},"Verificar_imagen_texto":{"main":[[{"node":"AI_gent_Citas","type":"main","index":0}]]},"When clicking ‘Execute workflow’":{"main":[[{"node":"Verificar_imagen_texto","type":"main","index":0}]]},"AI_gent_Citas":{"main":[[]]},"Merge":{"main":[[{"node":"Code in JavaScript","type":"main","index":0}]]},"Postgres Chat Memory":{"ai_memory":[[{"node":"AI_gent_Citas","type":"ai_memory","index":0}]]}}', '2025-12-21 10:21:51.925+00', '2026-02-12 21:12:12.498+00', '{"executionOrder":"v1"}', NULL, '{"When clicking ‘Execute workflow’":[{"json":{"text":"quiero agendar una ita","session_id":"584142711347","platform":"whatsapp","image_url":""}}]}', 'e58040a1-07b2-4367-97d1-7962ceba2c8f', 0, '44Hf0tLv7msSiroV', '{"templateCredsSetupCompleted":true}', 'U9r95Q5njBlyLM0X', false, 192, NULL, 'e58040a1-07b2-4367-97d1-7962ceba2c8f');
