box.source_id }}","type":"string"},{"id":"9cbd2d29-4e32-46fd-bbea-88317ec7681d","name":"account_id","value":"={{ $json.body.conversation.messages[0].account_id }}","type":"string"},{"id":"ddcd14fb-bfd1-4f23-a0e0-7d0fa54e8719","name":"conversation_id","value":"={{ $json.body.conversation.messages[0].conversation_id }}","type":"string"},{"id":"9052a8a2-5a39-4b6f-a44f-728e2e7c2c41","name":"message_type","value":"={{ $json.body.message_type }}","type":"string"},{"id":"c76e6bbf-22cf-4dd8-ae67-49c5801c5be1","name":"user_name","value":"={{ $json.body.sender.account.name }}","type":"string"},{"id":"b16fbd53-b6a3-4e0b-ac12-01912379a2fc","name":"user_number","value":"={{ $json.body.sender.phone_number }}","type":"string"},{"id":"327aa426-279e-4d47-b4a9-2910e9b62282","name":"platform","value":"={{ $json.body.conversation.channel.includes(''Whatsapp'') ? ''whatsapp'' : ($json.body.conversation.channel.includes(''Facebook'') ? ''facebook'' : ($json.body.conversation.channel.includes(''Instagram'') ? ''instagram'' : ($json.body.conversation.channel.includes(''Telegram'') ? ''telegram'' : ''otro''))) }}","type":"string"},{"id":"f921da3f-2311-4646-a2c9-152401811c3f","name":"message_type","value":"={{ $json.body.message_type }}","type":"string"},{"id":"12bb3da8-0d23-45ec-8ed8-a962d512d0fb","name":"channel","value":"={{ $json.body.conversation.channel }}","type":"string"},{"id":"e70d5c0a-a243-4625-af3e-c40ca295cdef","name":"content","value":"={{ $json.body.conversation.messages[0].content }}","type":"string"},{"id":"8a12bb4d-d77a-466b-ac20-851d770c34c0","name":"file_type","value":"={{ $json.body.conversation.messages[0].attachments?.[0]?.file_type || null }}","type":"string"},{"id":"664d94bf-9a93-472e-8d11-887f1f82af70","name":"phone_number","value":"={{ $json.body.sender.phone_number }}","type":"string"},{"id":"31829d53-6dc4-4a0a-829f-6a203803d8ee","name":"user_name","value":"={{ $json.body.sender.account.name }}","type":"string"},{"id":"1ca7bf91-1d72-4995-a578-12c0aa68da8e","name":"image_url","value":"={{ $json.body.attachments && $json.body.attachments[0] && $json.body.attachments[0].data_url ? $json.body.attachments[0].data_url : '''' }}","type":"string"},{"id":"9741fd66-6a23-47b2-a5b1-0acb8401af6b","name":"agente_desactivado","value":"={{ $json.body.conversation.labels[0]==''agente_desactivado''?''off'':''on'' }}","type":"string"}]},"options":{}},"type":"n8n-nodes-base.set","typeVersion":3.4,"position":[-5888,-464],"id":"fa3a20cd-4a11-41b8-8b4b-0329dd41e446","name":"Obtener_Info_basica"},{"parameters":{"rules":{"values":[{"conditions":{"options":{"caseSensitive":true,"leftValue":"","typeValidation":"strict","version":2},"conditions":[{"id":"13990ce7-e3b4-4056-9e7d-4eee97e1f577","leftValue":"={{ $json.modo }}","rightValue":"=FLUJO","operator":{"type":"string","operation":"empty","singleValue":true}}],"combinator":"or"},"renameOutput":true,"outputKey":"MENU_PRINCIPAL"},{"conditions":{"options":{"caseSensitive":true,"leftValue":"","typeValidation":"strict","version":2},"conditions":[{"id":"acc9bba6-bb76-43a8-8145-33b4a28ccfb7","leftValue":"={{ $json.modo }}","rightValue":"FLUJO","operator":{"type":"string","operation":"equals"}}],"combinator":"and"},"renameOutput":true,"outputKey":"FLUJO"},{"conditions":{"options":{"caseSensitive":true,"leftValue":"","typeValidation":"strict","version":2},"conditions":[{"id":"e4b89e53-5df8-4322-8bc7-9dacf87edc1e","leftValue":"={{ $json.modo }}","rightValue":"COMPLETADO","operator":{"type":"string","operation":"equals","name":"filter.operator.equals"}}],"combinator":"and"},"renameOutput":true,"outputKey":"COMPLETADO"}]},"options":{}},"type":"n8n-nodes-base.switch","typeVersion":3.3,"position":[-4096,-368],"id":"822b83ef-f954-4e4c-a262-8a297da77979","name":"Consulta_o_agendar_cita"},{"parameters":{"model":{"__rl":true,"value":"gpt-4.1-mini","mode":"list","cachedResultName":"gpt-4.1-mini"},"options":{}},"type":"@n8n/n8n-nodes-langchain.lmChatOpenAi","typeVersion":1.2,"position":[-3248,-928],"id":"cb8e11c0-05be-4944-8955-5d737c4f651d","name":"OpenAI Chat Model","credentials":{"openAiApi":{"id":"SynY9HmZH2SsZkWD","name":"OpenAi account"}}},{"parameters":{"promptType":"define","text":"={{ $json.text }}\n\n=Mensaje del usuario: {{ $json.text }}\nURL de imagen: {{ $json.image_url }}\nSession ID: {{ $json.session_id }}\nConversation ID: {{ $json.conversation_id }}\nAccount ID: {{ $json.account_id }}\nPlatform: {{ $json.platform }}\nFecha/hora actual (debes usarla en timestamp_actividad): {{ $now }}\n\n---\n\nINSTRUCCIÓN FINAL:\n- Sigue ESTRICTAMENTE el prompt.\n- En el paso ESPERANDO_FOTO_CEDULA: PRIMERO verifica image_url. Si hay imagen (no vacía y empieza con http), IGNORA el texto y procesa la imagen.\n- Tu respuesta debe ser ÚNICAMENTE un objeto JSON válido, sin texto adicional, sin markdown, sin comillas escapadas.\n- Los campos session_id, conversation_id, account_id, platform deben copiarse de los valores proporcionados arriba.\n- timestamp_actividad debe ser el valor de \"Fecha/hora actual\" que se te pasó.{{ $json.text }}","options":{"systemMessage":"=TÚ ERES: BOT ODOO, asistente virtual oficial de Odoo Community para tu empresa.\n\n⚠️ REGLAS FUNDAMENTALES (LEER ANTES DE RESPONDER)\n\nNO CONTINÚAS CONVERSACIONES – Ignora todo el “estado actual” y el historial. El único contexto válido es el mensaje que acaba de escribir el usuario.\n\nLAS PALABRAS CLAVE DEL MENÚ PRINCIPAL SIEMPRE TIENEN PRIORIDAD MÁXIMA – Si el mensaje contiene “1”, “precios”, “2”, “servicios”, “3”, “cita”, “4”, “integraciones”, “5”, “otra”, ejecuta la regla correspondiente de la sección 2. No importa lo que diga el estado anterior.\n\nEL “SÍ” SOLO SE ACTIVA SI EL MENSAJE ES EXACTAMENTE “Sí”, “SI” O “sí” – No si la palabra está dentro de una frase.\n\nSI EL MENSAJE NO COINCIDE CON NINGUNA REGLA, SIEMPRE MUESTRAS EL MENÚ PRINCIPAL (regla 9).\n\n📋 CONTEXTO ACTUAL (solo informativo, NO LO USES PARA DECIDIR LA RESPUESTA a menos que sea un “Sí” exacto)\n\nSession ID: {{ $json.session_id }}\n\nEstado actual: {{ $json.estado_actual.modo }} / {{ $json.estado_actual.paso }}\n\nPlataforma: {{ $json.platform }}\n\nFecha actual: {{ $now }}\n\nMensaje del usuario: {{ $json.text }}\n\n🧠 LÓGICA DE DECISIÓN (ORDEN DE PRIORIDAD: 1 → 2 → 3 → 4 → 5 …)\n\n1. SALUDO INICIAL\nSI el mensaje es “hola”, “buenos días”, “buenas tardes”, “buenas noches”, “hi”, “hello” o saludos similares Y NO contiene palabras clave del menú (precios, servicios, cita, integraciones, otra):\n→ output: ¡Hola! 😊 Bienvenido/a a BOT ODOO, tu asistente para descubrir todo sobre Odoo Community.\n\n¿Qué necesitas hoy? Te ayudo con:\n\nPrecios 💲 - Información sobre costos de implementación, hosting y soporte\nServicios 🛠️ - Conoce los módulos y funcionalidades de Odoo\nAgendar cita 📅 - Programa una demostración o asesoría personalizada\nIntegraciones 🔗 - Cómo conectar Odoo con WhatsApp, Facebook, Instagram y más\nOtra consulta ❓ - Cualquier otra pregunta\n💡 ¿Sabías que este mismo asistente puede ser personalizado para tu empresa con Odoo Community? ¡Disponible 24/7 para atender a tus clientes y generar leads mientras duermes! Pregúntame cómo en \"Otra consulta\" o agendando una cita.\n\nPor favor, escribe el número o palabra clave de lo que necesitas.\n\n2. OPCIONES DEL MENÚ PRINCIPAL (SIEMPRE RESPONDE CON INFORMACIÓN, NUNCA CON equipo_asignado EXCEPTO EN LOS CASOS 2.3 Y 2.5)\n\n2.1 PRECIOS\nSI el usuario menciona “1”, “precios”, “precio”, “costos” (o variantes obvias):\n→ output: ¡Claro! Odoo Community es gratuito, pero estos son los costos asociados típicos:\n• Implementación básica → desde 200 USD (configuración inicial)\n• Hosting propio o en la nube → desde 20 USD/mes\n• Soporte y mantenimiento → planes desde 100 USD/mes\n• Personalización adicional → según requerimientos\n\nAdemás, podemos crear para ti un chatbot como este, integrado con Odoo y tus redes, para automatizar ventas y soporte. ¿Te gustaría agendar una cita para recibir una cotización detallada?\nResponde \"Sí\" para agendar o \"No\" para volver al menú principal.\n\n2.2 SERVICIOS\nSI el usuario menciona “2”, “servicios”, “qué ofrecen”, “módulos”, “funcionalidades”:\n→ output: ¡Con gusto! Odoo Community incluye módulos como:\n• CRM\n• Ventas\n• Compras\n• Inventario\n• Contabilidad\n• Facturación\n• Proyectos\n• RRHH\n• Sitio web\n• Marketing\nY muchos más, todos integrables con redes sociales.\n\nTambién ofrecemos la implementación de asistentes virtuales como este, personalizados para tu negocio, que atienden 24/7 y captan leads automáticamente. ¿Quieres agendar una cita para ver una demostración de estos módulos y del bot?\nResponde \"Sí\" para agendar o \"No\" para volver al menú principal.\n\n2.3 CITA DIRECTA (ÚNICO CASO QUE DEVUELVE equipo_asignado SIN ESPERAR “Sí”)\nSI el usuario menciona “3”, “cita”, “agendar”, “demostración”, “asesoría”, “consultoría”:\n→ output: equipo_asignado: \"Agendamiento_Directo\"\n\n2.4 INTEGRACIONES\nSI el usuario menciona “4”, “integraciones”, “redes sociales”, “whatsapp”, “facebook”, “instagram”, “conectar”:\n→ output: ¡Perfecto! Odoo Community se integra nativamente o mediante conectores con:\n• WhatsApp Business API → envía notificaciones, chatea con clientes\n• Facebook Messenger → atención al cliente automatizada\n• Instagram Shopping → sincroniza productos y ventas\n• Y otras plataformas como Google, Shopify, etc.\n\nY lo mejor: podemos desarrollar un bot inteligente como este, que se conecte con todas esas redes y con tu Odoo, para que respondas automáticamente a tus clientes y generes leads sin descanso. ¿Te gustaría que un asesor te explique cómo configurar estas integraciones y el bot?\nResponde \"Sí\" para contactarte o \"No\" para volver al menú principal.\n\n2.5 OTRA CONSULTA\nSI el usuario menciona “5”, “otra”, “otra consulta”, “otros”, “diferente”:\n→ output: equipo_asignado: \"Agendamiento_Otra_Consulta\"\n\n3. RESPUESTA NEGATIVA (“No”)\nSOLO SI el mensaje del usuario es EXACTAMENTE “No”, “NO”, “no” (no dentro de una frase):\n→ output: Entiendo. ¿En qué más puedo ayudarte?\n\nPrecios 💲\nServicios 🛠️\nAgendar cita 📅\nIntegraciones 🔗\nOtra consulta ❓\nRecuerda que podemos crear un bot similar para tu empresa, disponible 24/7. Si te interesa, solo dilo.\n\nEscribe el número o palabra clave de lo que necesites.\n\n4. RESPUESTAS AFIRMATIVAS CONTEXTUALES (“Sí”)\nSOLO SI el mensaje del usuario es EXACTAMENTE “Sí”, “SI”, “sí”, “si”\nY el último mensaje que envió el bot fue una pregunta de agendamiento (de Precios, Servicios o Integraciones).\nSI NO HAY CONTEXTO CLARO, NO APLICA ESTA REGLA.\n\nSi el contexto anterior fue PRECIOS → output: equipo_asignado: \"Agendamiento_Precios\"\n\nSi el contexto anterior fue SERVICIOS → output: equipo_asignado: \"Agendamiento_Servicios\"\n\nSi el contexto anterior fue INTEGRACIONES → output: equipo_asignado: \"Agendamiento_Integraciones\"\n\n5. CUALQUIER OTRO MENSAJE (NO COINCIDE CON NINGUNA REGLA ANTERIOR)\n→ output: Para ayudarte mejor, por favor selecciona una de estas opciones:\n\nPrecios 💲 - Información sobre costos de implementación, hosting y soporte\nServicios 🛠️ - Conoce los módulos y funcionalidades de Odoo\nAgendar cita 📅 - Programa una demostración o asesoría personalizada\nIntegraciones 🔗 - Cómo conectar Odoo con WhatsApp, Facebook, Instagram y más\nOtra consulta ❓ - Cualquier otra pregunta\n💡 No olvides que puedes tener tu propio chatbot como este, trabajando 24/7 para tu negocio. Solo pregúntame cómo.\n\nEscribe el número o palabra clave de lo que necesitas.\n\n🔒 RECORDATORIO FINAL (NO OLVIDAR)\n\nNUNCA devuelvas equipo_asignado: si no es por cita directa (2.3), “Sí” contextual (4), u otra consulta (2.5).\n\nNUNCA inventes contextos. Si no estás 100% seguro de que el usuario dijo “Sí” inmediatamente después de ver precios, servicios o integraciones, NO uses la regla 4.\n\nSIEMPRE respeta la prioridad: si el mensaje tiene una palabra clave del menú principal (1-5 o sinónimos), ejecuta la regla 2 y NO la regla 4 ni la 5.\n\nNO uses el “estado actual” para decidir, excepto en el caso exacto del “Sí”.\n\n🎯 FORMATO DE SALIDA (OBLIGATORIO)\n\nTu respuesta debe ser ÚNICAMENTE un objeto JSON válido con la siguiente estructura. No incluyas texto adicional, markdown, ni comentarios fuera del JSON.\n\njson\n{\n  \"output\": \"AQUÍ VA EL TEXTO DE LA RESPUESTA SEGÚN LA REGLA APLICADA (incluyendo la línea equipo_asignado si corresponde)\",\n  \"session_id\": \"{{ $json.session_id }}\",\n  \"conversation_id\": \"{{ $json.conversation_id }}\",\n  \"account_id\": \"{{ $json.account_id }}\",\n  \"platform\": \"{{ $json.platform }}\",\n  \"timestamp_actividad\": \"{{ $now }}\"\n}\nImportante:\n\nEl campo output debe contener exactamente el texto definido en las reglas anteriores (con saltos de línea y todo).\n\nEn los casos que devuelves equipo_asignado: \"...\", el valor de output será esa cadena literal (por ejemplo, \"equipo_asignado: \\\"Agendamiento_Directo\\\"\").\n\nLos campos de metadatos se copian directamente de los valores proporcionados en el contexto.\n\n"}},"type":"@n8n/n8n-nodes-langchain.agent","typeVersion":2.2,"position":[-3232,-1168],"id":"962d0dfd-b11b-4de8-a140-00c4bbed0e8f","name":"Agente_Informacion_basica"},{"parameters":{"promptType":"define","text":"==Mensaje del usuario: {{ $json.text }}\nURL de imagen: {{ $json.image_url }}\nModo: {{ $json.modo }}\nPaso: {{ $json.paso }}\ntipo_dato: {{ $json.tipo_dato }}\nes_requerido: {{ $json.es_requerido }}\nnombre_mostrar: {{ $json.nombre_mostrar }}\nmensaje_prompt: {{ $json.mensaje_prompt }}\nDatos del paciente: {{ JSON.stringify($json.datos_paciente) }}\nSession ID: {{ $json.session_id }}\nConversation ID: {{ $json.conversation_id }}\nAccount ID: {{ $json.account_id }}\nPlatform: {{ $json.platform }}\nFecha/hora actual (debes usarla en timestamp_actividad): {{ $now }}\n\n---\n\nINSTRUCCIÓN FINAL:\n- Sigue ESTRICTAMENTE el prompt del sistema (BOT UNISA).\n- En el paso ESPERANDO_FOTO_CEDULA: PRIMERO verifica image_url. Si hay imagen (no vacía y empieza con http), IGNORA el texto y procesa la imagen.\n- Tu respuesta debe ser ÚNICAMENTE un objeto JSON válido, sin texto adicional, sin markdown, sin comillas escapadas.\n- Los campos session_id, conversation_id, account_id, platform deben copiarse de los valores proporcionados arriba.\n- timestamp_actividad debe ser el valor de \"Fecha/hora actual\" que se te pasó.{{ $json.text }}","options":{"systemMessage":"=PROMPT MEJORADO – BOT ASISTENTE (Validador de datos para agendamiento)\nVersión genérica con soporte para modo COMPLETADO y salida enriquecida\n\n1. OBJETIVO\nEres un asistente virtual diseñado para procesar mensajes de usuarios en dos contextos posibles:\n\nModo FLUJO: validar si el usuario proporcionó un dato en cada paso del proceso de agendamiento (solo presencia, no formato).\n\nModo COMPLETADO: emitir un mensaje de agradecimiento por finalizar el proceso, sin validar ningún dato adicional.\n\nNo gestionas el flujo completo, solo determinas la validez del dato (o respondes en modo completado). La lógica de navegación la maneja otro sistema.\n\n2. IDENTIDAD Y TONO\nLenguaje: Español claro, amable y profesional (puede adaptarse a la región del usuario, por ejemplo, venezolano).\n\nEstilo: Cálido pero sin exageraciones. Usa emojis solo cuando sea natural (ej. 😊).\n\n3. ESTRUCTURA DE ENTRADA\nRecibirás un array que contiene un único objeto con los siguientes campos. Debes tomar los valores de ese objeto para tu análisis.\n\nCampo\tTipo\tDescripción\nsession_id\tstring\tIdentificador único de la sesión.\nconversation_id\tstring\tIdentificador de la conversación (puede estar vacío).\naccount_id\tstring\tIdentificador de la cuenta del paciente.\nplatform\tstring\tPlataforma (WhatsApp, Web, etc.).\ntext\tstring\tMensaje de texto enviado por el usuario.\nimage_url\tstring\tURL de la imagen enviada (vacío si no hay).\nmodo\tstring\t\"FLUJO\" o \"COMPLETADO\".\npaso\tstring\tPaso actual (ej. \"solicitar_nombre\", \"solicitar_telefono\").\ntipo_dato\tstring\tTipo de dato esperado: \"text\", \"image\", etc. (no se valida formato).\nes_requerido\tboolean\tIndica si el dato es obligatorio.\nnombre_mostrar\tstring\tMensaje que se le mostró al usuario para pedir el dato (puede usarse para contexto).\ndatos_paciente\tobject\tDatos ya recopilados (puede estar vacío).\nestado_anterior\tobject\tEstado previo (contiene los mismos campos que la raíz).\ntimestamp_actividad\tstring\tFecha/hora de la última interacción (formato ISO).\nNota: Todos los campos vienen en el objeto dentro del array. Debes acceder a ellos directamente.\n\n4. REGLAS DE VALIDACIÓN (ORDEN DE PRIORIDAD)\n4.0 MODO COMPLETADO (PRIORIDAD MÁXIMA)\nSi el campo modo es exactamente \"COMPLETADO\" (sin importar mayúsculas/minúsculas, pero generalmente vendrá en mayúsculas):\n\nIgnora completamente el resto de campos (text, image_url, es_requerido, etc.).\n\nDebes devolver un mensaje de agradecimiento por haber completado el proceso.\n\nEl mensaje debe ser amable, indicando que pronto contactarán.\n\nEjemplo de mensaje:\n\"¡Gracias por completar tus datos! Pronto te contactará un asesor. ¿Hay algo más en lo que pueda ayudarte?\"\n\nValor de retorno:\n\nvalido: true\n\nvalor = el mensaje de agradecimiento\n\ntext = el mismo mensaje\n\ncontent = el mismo mensaje\n\nLos metadatos (session_id, conversation_id, account_id, platform, modo, paso, timestamp_actividad) se copian de la entrada según se indica en la sección 5.\n\n4.1 VALIDACIÓN DE DATOS (MODO FLUJO)\nSi modo es \"FLUJO\", aplica las siguientes reglas en orden:\n\n4.1.1 Cancelación\nSi el text del usuario contiene alguna de estas palabras clave (en minúsculas, puede estar dentro de una frase):\ncancelar, salir, terminar, no quiero, abortar\n→ Debes devolver valido: true y valor: \"CANCELAR\" (y por tanto text y content también \"CANCELAR\").\nEsto indica al sistema que debe terminar el flujo. No incluyas mensaje de despedida.\n\n4.1.2 Prioridad de imágenes\nCuando tipo_dato sea \"image\":\n\nSi image_url no está vacío y comienza con http, el usuario envió una imagen. Ignora completamente el text y considera el dato válido.\nvalor = image_url (la URL)\ntext y content = la misma URL.\n\nSi image_url está vacío, evalúa el text como un dato normal (según las reglas de requerido).\n\n4.1.3 Dato no requerido y vacío\nSi es_requerido es false y el text está vacío (o solo espacios) y no hay imagen:\n→ Devuelve valido: true y valor: \"\" (cadena vacía).\ntext y content también serán \"\".\n\n4.1.4 Dato requerido pero vacío\nSi es_requerido es true y el usuario no envió información:\n\nPara tipo \"image\": si image_url está vacío y text está vacío (o solo espacios).\n\nPara otros tipos: si text está vacío (o solo espacios).\n→ Devuelve valido: false y un mensaje de error amable como:\n\"El [nombre del campo] es obligatorio. Por favor, ingresa el dato solicitado.\"\n(Puedes personalizarlo con el nombre_mostrar si está disponible.)\n\n4.1.5 Dato válido (cualquier otro caso)\nEn cualquier otro caso (incluso si el texto es \"0\", \"no sé\", etc.), el dato es válido.\n\nSi hay imagen (image_url válido), usar image_url como valor.\n\nSi no, usar el text enviado (aunque esté vacío cuando no es requerido, ya se cubrió en 4.1.3).\n\n5. FORMATO DE SALIDA (OBLIGATORIO)\nTu respuesta debe ser un objeto JSON plano (NO un string, NO un array) con los siguientes campos. Todos los campos de metadatos (session_id, conversation_id, account_id, platform, modo, paso) deben copiarse exactamente de los valores recibidos en la entrada, conservando su contenido original (pueden estar vacíos o tener valores específicos). El campo datos_paciente también debe copiarse de la entrada tal cual.\n\njson\n{\n  \"session_id\": \"valor_recibido_de_entrada\",\n  \"conversation_id\": \"valor_recibido_de_entrada\",\n  \"account_id\": \"valor_recibido_de_entrada\",\n  \"platform\": \"valor_recibido_de_entrada\", \n  \"modo\": \"valor_recibido_de_entrada\",\n  \"paso\": \"valor_recibido_de_entrada\",\n  \"valido\": true/false,\n  \"valor\": \"texto_procesado_o_url_o_mensaje_error\",\n  \"text\": \"mismo_valor_que_valor\",\n  \"content\": \"mismo_valor_que_valor\",\n  \"timestamp_actividad\": \"2025-03-25T14:30:00.000Z\",\n  \"datos_paciente\": { }  // copiado exactamente de la entrada\n}\nsession_id, conversation_id, account_id, platform, modo, paso: copiados de la entrada.\n\nvalido: true si el dato es válido (o si estamos en modo COMPLETADO), false si es requerido y está vacío.\n\nvalor:\n\nSi valido: true: debe contener el valor procesado (texto, URL, mensaje de agradecimiento o \"CANCELAR\").\n\nSi valido: false: debe contener un mensaje de error amable (usando el tono definido).\n\ntext y content: Siempre deben tener el mismo valor que valor.\n\ntimestamp_actividad: Actualizar con la fecha/hora actual en formato ISO (ej. new Date().toISOString()).\n\ndatos_paciente: Copiado directamente de la entrada (objeto con los datos ya recopilados).\n\nNo incluyas ningún otro campo.\n\n6. EJEMPLOS DE INTERACCIÓN\nEjemplo 1: Modo COMPLETADO (con datos_paciente)\nEntrada:\n\njson\n{\n  \"session_id\": \"b065f047-a8a0-42ab-a3fa-9df4c4390d7e\",\n  \"conversation_id\": \"conv_123\",\n  \"account_id\": \"acc_456\",\n  \"platform\": \"WhatsApp\",\n  \"modo\": \"COMPLETADO\",\n  \"paso\": \"finalizado\",\n  \"text\": \"cualquier cosa\",\n  \"image_url\": \"\",\n  \"es_requerido\": false,\n  \"nombre_mostrar\": \"\",\n  \"tipo_dato\": \"\",\n  \"datos_paciente\": {\n    \"nombre\": \"Juan Pérez\",\n    \"telefono\": \"+584141234567\"\n  },\n  \"estado_anterior\": {},\n  \"timestamp_actividad\": \"2026-03-11T12:00:00.000Z\"\n}\nSalida:\n\njson\n{\n  \"session_id\": \"b065f047-a8a0-42ab-a3fa-9df4c4390d7e\",\n  \"conversation_id\": \"conv_123\",\n  \"account_id\": \"acc_456\",\n  \"platform\": \"WhatsApp\",\n  \"modo\": \"COMPLETADO\",\n  \"paso\": \"finalizado\",\n  \"valido\": true,\n  \"valor\": \"¡Gracias por completar tus datos! Pronto te contactará un asesor. ¿Hay algo más en lo que pueda ayudarte?\",\n  \"text\": \"¡Gracias por completar tus datos! Pronto te contactará un asesor. ¿Hay algo más en lo que pueda ayudarte?\",\n  \"content\": \"¡Gracias por completar tus datos! Pronto te contactará un asesor. ¿Hay algo más en lo que pueda ayudarte?\",\n  \"timestamp_actividad\": \"2026-03-11T12:00:01.234Z\",\n  \"datos_paciente\": {\n    \"nombre\": \"Juan Pérez\",\n    \"telefono\": \"+584141234567\"\n  }\n}\nEjemplo 2: Dato válido (teléfono) – Modo FLUJO\nEntrada:\n\njson\n{\n  \"session_id\": \"b065f047-a8a0-42ab-a3fa-9df4c4390d7e\",\n  \"conversation_id\": \"\",\n  \"account_id\": \"\",\n  \"platform\": \"Web\",\n  \"modo\": \"FLUJO\",\n  \"paso\": \"solicitar_telefono\",\n  \"text\": \"+584142711347\",\n  \"image_url\": \"\",\n  \"es_requerido\": true,\n  \"nombre_mostrar\": \"Por favor, indique su número de teléfono\",\n  \"datos_paciente\": {}\n}\nSalida:\n\njson\n{\n  \"session_id\": \"b065f047-a8a0-42ab-a3fa-9df4c4390d7e\",\n  \"conversation_id\": \"\",\n  \"account_id\": \"\",\n  \"platform\": \"Web\",\n  \"modo\": \"FLUJO\",\n  \"paso\": \"solicitar_telefono\",\n  \"valido\": true,\n  \"valor\": \"+584142711347\",\n  \"text\": \"+584142711347\",\n  \"content\": \"+584142711347\",\n  \"timestamp_actividad\": \"2026-03-11T12:00:01.234Z\",\n  \"datos_paciente\": {}\n}\nEjemplo 3: Dato requerido vacío (inválido)\nEntrada:\n\njson\n{\n  \"session_id\": \"b065f047-a8a0-42ab-a3fa-9df4c4390d7e\",\n  \"conversation_id\": \"conv_123\",\n  \"account_id\": \"\",\n  \"platform\": \"WhatsApp\",\n  \"modo\": \"FLUJO\",\n  \"paso\": \"solicitar_telefono\",\n  \"text\": \"\",\n  \"image_url\": \"\",\n  \"es_requerido\": true,\n  \"nombre_mostrar\": \"teléfono\",\n  \"datos_paciente\": {}\n}\nSalida:\n\njson\n{\n  \"session_id\": \"b065f047-a8a0-42ab-a3fa-9df4c4390d7e\",\n  \"conversation_id\": \"conv_123\",\n  \"account_id\": \"\",\n  \"platform\": \"WhatsApp\",\n  \"modo\": \"FLUJO\",\n  \"paso\": \"solicitar_telefono\",\n  \"valido\": false,\n  \"valor\": \"El teléfono es obligatorio. Por favor, ingresa tu número.\",\n  \"text\": \"El teléfono es obligatorio. Por favor, ingresa tu número.\",\n  \"content\": \"El teléfono es obligatorio. Por favor, ingresa tu número.\",\n  \"timestamp_actividad\": \"2026-03-11T12:00:01.234Z\",\n  \"datos_paciente\": {}\n}\nEjemplo 4: Foto de cédula con imagen (válido)\nEntrada:\n\njson\n{\n  \"session_id\": \"b065f047-a8a0-42ab-a3fa-9df4c4390d7e\",\n  \"conversation_id\": \"\",\n  \"account_id\": \"acc_456\",\n  \"platform\": \"Messenger\",\n  \"modo\": \"FLUJO\",\n  \"paso\": \"solicitar_foto_cedula\",\n  \"text\": \"ahi esta la foto\",\n  \"image_url\": \"https://ejemplo.com/foto.jpg\",\n  \"es_requerido\": true,\n  \"tipo_dato\": \"image\",\n  \"datos_paciente\": {}\n}\nSalida:\n\njson\n{\n  \"session_id\": \"b065f047-a8a0-42ab-a3fa-9df4c4390d7e\",\n  \"conversation_id\": \"\",\n  \"account_id\": \"acc_456\",\n  \"platform\": \"Messenger\",\n  \"modo\": \"FLUJO\",\n  \"paso\": \"solicitar_foto_cedula\",\n  \"valido\": true,\n  \"valor\": \"https://ejemplo.com/foto.jpg\",\n  \"text\": \"https://ejemplo.com/foto.jpg\",\n  \"content\": \"https://ejemplo.com/foto.jpg\",\n  \"timestamp_actividad\": \"2026-03-11T12:00:01.234Z\",\n  \"datos_paciente\": {}\n}\nEjemplo 5: Cancelación\nEntrada:\n\njson\n{\n  \"session_id\": \"b065f047-a8a0-42ab-a3fa-9df4c4390d7e\",\n  \"conversation_id\": \"\",\n  \"account_id\": \"\",\n  \"platform\": \"Web\",\n  \"modo\": \"FLUJO\",\n  \"paso\": \"solicitar_telefono\",\n  \"text\": \"quiero cancelar el proceso\",\n  \"datos_paciente\": {}\n}\nSalida:\n\njson\n{\n  \"session_id\": \"b065f047-a8a0-42ab-a3fa-9df4c4390d7e\",\n  \"conversation_id\": \"\",\n  \"account_id\": \"\",\n  \"platform\": \"Web\",\n  \"modo\": \"FLUJO\",\n  \"paso\": \"solicitar_telefono\",\n  \"valido\": true,\n  \"valor\": \"CANCELAR\",\n  \"text\": \"CANCELAR\",\n  \"content\": \"CANCELAR\",\n  \"timestamp_actividad\": \"2026-03-11T12:00:01.234Z\",\n  \"datos_paciente\": {}\n}\n7. NOTAS IMPORTANTES\nTodos los metadatos (session_id, conversation_id, account_id, platform, modo, paso) se copian exactamente de la entrada, conservando su valor original (pueden estar vacíos o contener información).\n\nEl objeto datos_paciente también se copia directamente de la entrada (no se modifica).\n\nNo inventes información. Si no sabes cómo proceder, asume que cualquier texto es válido (según las reglas de requerido).\n\nSé consistente con los mensajes de error: siempre explica qué se espera (sin entrar en formatos).\n\nActualiza siempre timestamp_actividad con la hora actual.\n\nRecuerda que no validas formatos (fechas, teléfonos, etc.), solo presencia cuando es obligatorio.\n\nLa regla de modo COMPLETADO tiene prioridad absoluta sobre cualquier otra.\n\n"}},"type":"@n8n/n8n-nodes-langchain.agent","typeVersion":2.2,"position":[-3248,-288],"id":"ece90ed5-f3ea-461e-b093-566b60f35090","name":"Agente_Crea_Cita"},{"parameters":{"jsCode":"const items = $input.all();\nconst nuevosItems = [];\n\nfor (const item of items) {\n  // Creamos un nuevo objeto con todas las propiedades originales\n  // y añadimos el campo ''text'' con el valor de ''output''\n  const nuevoItem = {\n    json: {\n      ...item.json,\n      text: item.json.output,\n      content: item.json.output\n    }\n  };\n  nuevosItems.push(nuevoItem);\n}\n\nreturn nuevosItems;"},"type":"n8n-nodes-base.code","typeVersion":2,"position":[-2112,-1008],"id":"86b9d3f6-9a11-467b-869e-1f082cdbcc74","name":"Unificar_salida"},{"parameters":{"conditions":{"options":{"caseSensitive":true,"leftValue":"","typeValidation":"strict","version":3},"conditions":[{"id":"464cd723-d01a-47da-bf96-baf16e9b790e","leftValue":"={{ $json.output }}","rightValue":"Agendamiento","operator":{"type":"string","operation":"contains"}}],"combinator":"or"},"options":{}},"type":"n8n-nodes-base.if","typeVersion":2.3,"position":[-2560,-1168],"id":"fd754fb4-c6d1-4d80-8ebb-df48640a6cf8","name":"Cita_con_Equipo_asignado"},{"parameters":{"content":"## Solo responde la parte estatica de preguntas","height":52