{"id":"message_type","displayName":"message_type","required":false,"defaultMatch":false,"display":true,"canBeUsedToMatch":true,"type":"string","removed":false},{"id":"user_name","displayName":"user_name","required":false,"defaultMatch":false,"display":true,"canBeUsedToMatch":true,"type":"string","removed":false},{"id":"user_number","displayName":"user_number","required":false,"defaultMatch":false,"display":true,"canBeUsedToMatch":true,"type":"string","removed":false},{"id":"platform","displayName":"platform","required":false,"defaultMatch":false,"display":true,"canBeUsedToMatch":true,"type":"string","removed":false},{"id":"channel","displayName":"channel","required":false,"defaultMatch":false,"display":true,"canBeUsedToMatch":true,"type":"string","removed":false},{"id":"content","displayName":"content","required":false,"defaultMatch":false,"display":true,"canBeUsedToMatch":true,"type":"string","removed":false},{"id":"file_type","displayName":"file_type","required":false,"defaultMatch":false,"display":true,"canBeUsedToMatch":true,"removed":false},{"id":"phone_number","displayName":"phone_number","required":false,"defaultMatch":false,"display":true,"canBeUsedToMatch":true,"removed":false},{"id":"user_message","displayName":"user_message","required":false,"defaultMatch":false,"display":true,"canBeUsedToMatch":true,"type":"string","removed":false},{"id":"image_url","displayName":"image_url","required":false,"defaultMatch":false,"display":true,"canBeUsedToMatch":true,"type":"string","removed":false},{"id":"agente_desactivado","displayName":"agente_desactivado","required":false,"defaultMatch":false,"display":true,"canBeUsedToMatch":true,"type":"boolean","removed":false}],"attemptToConvertTypes":false,"convertFieldsToString":true},"options":{}},"type":"n8n-nodes-base.executeWorkflow","typeVersion":1.3,"position":[-4480,208],"id":"ae7108fb-02a7-4121-bc95-637c4e46989f","name":"Call ''chatbot-simple_1_subflow''"},{"parameters":{"method":"POST","url":"https://integraiadev.integraia.lat/chat_bot_integra/inicioagendar","sendBody":true,"specifyBody":"json","jsonBody":"={\n  \"session_id\": \"{{ $json.session_id }}\",\n   \"name_flow\": \"flujoprueba\",\n   \"equipo_asignado\": \"{{$json.equipo_asignado|| \"\"}}\"\n \n} ","options":{}},"type":"n8n-nodes-base.httpRequest","typeVersion":4.3,"position":[-2128,-1328],"id":"58a835c5-b290-480f-a6f3-c0aeed1695b9","name":"paso_0_inicio_agendar","alwaysOutputData":true},{"parameters":{"jsCode":"const items = $input.all();\nconst nuevosItems = [];\n\nfor (const item of items) {\n  try {\n    let str = item.json.output;\n\n    // Reemplazar escapes Unicode compuestos del estilo \\u{1F6E0\\uFE0F}\n    str = str.replace(/\\\\u\\{([^}]+)\\}/g, (match, inner) => {\n      const parts = inner.split(/\\\\u/);\n      let result = '''';\n      for (let part of parts) {\n        if (part === '''') continue;\n        result += String.fromCodePoint(parseInt(part, 16));\n      }\n      return result;\n    });\n\n    // Parsear el JSON principal\n    const datosParseados = JSON.parse(str);\n\n    // Verificar si existe la propiedad \"output\" y si contiene el patrón equipo_asignado: \"valor\"\n    if (datosParseados.output && typeof datosParseados.output === ''string'') {\n      const match = datosParseados.output.match(/^\\s*equipo_asignado:\\s*\"([^\"]*)\"\\s*$/);\n      if (match) {\n        // Agregar la nueva propiedad \"equipo_asignado\" con el valor extraído\n        datosParseados.equipo_asignado = match[1];\n      }\n    }\n\n    // Agregar el objeto enriquecido a la salida\n    nuevosItems.push({ json: datosParseados });\n\n  } catch (e) {\n    // Si falla, devolver información del error\n    nuevosItems.push({\n      json: {\n        error: e.message,\n        original: item.json.output\n      }\n    });\n  }\n}\n\nreturn nuevosItems;"},"type":"n8n-nodes-base.code","typeVersion":2,"position":[-2880,-1168],"id":"a32304aa-7350-4780-912e-48d6ef97808f","name":"Separar_variables_en_json"},{"parameters":{"assignments":{"assignments":[{"id":"dda4884d-04e1-451c-b3af-f5a3183f2580","name":"session_id","value":"={{ $json.session_id }}","type":"string"},{"id":"70bff820-cfc3-4071-bcaa-4478eb7828e9","name":"conversation_id","value":"={{ $(''Cita_con_Equipo_asignado'').item.json.conversation_id }}","type":"string"},{"id":"d80d48b5-7d3e-4e34-bf33-cf46fa3b4e5d","name":"account_id","value":"={{ $(''Cita_con_Equipo_asignado'').item.json.account_id }}","type":"string"},{"id":"d784b741-4e38-4288-9223-4974592d75fb","name":"platform","value":"={{ $(''Cita_con_Equipo_asignado'').item.json.platform }}","type":"string"},{"id":"1021f53b-9c20-4d37-abf1-1622ce5bbd86","name":"text","value":"={{ $json.steps[0].nombre_mostrar }}","type":"string"},{"id":"4046b530-a78d-4676-b4ad-f2f8f2f81919","name":"output","value":"={{ $json.steps[0].nombre_mostrar }}","type":"string"},{"id":"0aebd45e-44c0-4633-9710-c3af2e6d9422","name":"content","value":"={{ $json.steps[0].nombre_mostrar }}","type":"string"}]},"options":{}},"type":"n8n-nodes-base.set","typeVersion":3.4,"position":[-1920,-1328],"id":"75aa2c07-6947-453c-b0d5-78a2ff9454cd","name":"Agendar_cita"},{"parameters":{"jsCode":"return items.map(item => {\n  try {\n    const parsed = JSON.parse(item.json.output);\n    return { json: parsed };\n  } catch (e) {\n    return {\n      json: {\n        success: false,\n        error: ''JSON inválido recibido del LLM'',\n        raw_output: item.json.output\n      }\n    };\n  }\n});\n"},"type":"n8n-nodes-base.code","typeVersion":2,"position":[-2816,-288],"id":"f6b03deb-699c-4df1-8653-c7a9e4dbe66d","name":"Arregla_json_valido"},{"parameters":{"method":"POST","url":"https://integraiadev.integraia.lat/chat_bot_integra/procesar_paso","sendBody":true,"bodyParameters":{"parameters":[{"name":"=session_id","value":"={{ $json.session_id }}"},{"name":"=valor"}]},"options":{}},"type":"n8n-nodes-base.httpRequest","typeVersion":4.3,"position":[-2864,-496],"id":"14a59015-c92a-4bef-a91b-b908b186629d","name":"HTTP Request","alwaysOutputData":true,"disabled":true,"onError":"continueErrorOutput"},{"parameters":{"method":"POST","url":"https://integraiadev.integraia.lat/chat_bot_integra/procesar_paso","sendBody":true,"specifyBody":"json","jsonBody":"={\n  \"session_id\": \"{{ $json.session_id }}\",\n   \"valor\": \"{{ $json.valor }}\",\n   \"paso\": \"{{ $json.paso }}\"\n} ","options":{}},"type":"n8n-nodes-base.httpRequest","typeVersion":4.3,"position":[-2192,-208],"id":"bf112d7f-d562-4a4c-82fd-c1373c2f8031","name":"procesar_paso","alwaysOutputData":true,"onError":"continueErrorOutput"},{"parameters":{"jsCode":"const items = $input.all();\n\nif (items.length === 0) {\n  throw new Error(''No se recibieron elementos'');\n}\n\nlet combinado;\n\nif (items.length === 1) {\n  combinado = { ...items[0].json };\n} else {\n  const contacto = items[0].json;\n  const flujo = items[1].json;\n  combinado = { ...contacto, ...flujo };\n}\n\n// 1. Prioridad: error\nif (combinado.error) {\n  combinado.text = combinado.error;\n  combinado.content = combinado.error;\n  combinado.valor = combinado.error;\n}\n// 2. Cancelación (valor CANCELAR)\nelse if (combinado.valor === \"CANCELAR\" || combinado.text === \"CANCELAR\" || combinado.content === \"CANCELAR\") {\n  const mensajeCancelacion = \"Gracias por tu interés. Has cancelado el proceso de agendamiento. Cuando quieras, puedes volver a empezar desde el menú principal. 😊\";\n  combinado.valor = mensajeCancelacion;\n  combinado.text = mensajeCancelacion;\n  combinado.content = mensajeCancelacion;\n}\n// 3. Flujo completado\nelse if (combinado.paso_actual === \"COMPLETADO\" || combinado.completado === true) {\n  const mensajeCompletado = \"¡Tus datos han sido registrados! Estamos procesando tu solicitud. Presiona cualquier tecla para continuar. 😊\";\n  combinado.text = mensajeCompletado;\n  combinado.content = mensajeCompletado;\n  combinado.valor = mensajeCompletado; // Opcional, para consistencia\n}\n// 4. nombre_mostrar (si existe y no hay cancelación ni completado)\nelse if (combinado.nombre_mostrar) {\n  combinado.text = combinado.nombre_mostrar;\n  combinado.content = combinado.nombre_mostrar;\n}\n// 5. En cualquier otro caso, se dejan los campos como están\n\nreturn [{ json: combinado }];"},"type":"n8n-nodes-base.code","typeVersion":2,"position":[-1296,-512],"id":"38f3491f-19a5-40d7-a2c6-90703492ddca","name":"Code in JavaScript"},{"parameters":{},"type":"n8n-nodes-base.merge","typeVersion":3.2,"position":[-1504,-512],"id":"ec7934e1-9838-49f4-aea2-f4d3a1a3475c","name":"Unir_data"},{"parameters":{"jsCode":"// Recorremos cada elemento de entrada\nfor (const item of $input.all()) {\n  // Inicializamos variable para el mensaje extraído\n  let mensajeExtraido = null;\n\n  // Verificamos si existe la estructura esperada\n  if (item.json.error && item.json.error.message) {\n    const mensajeCompleto = item.json.error.message;\n\n    // Buscamos el inicio del JSON (después del código de estado y el espacio)\n    // El formato típico: \"400 - {\\\"success\\\": false, ...}\"\n    const indiceJson = mensajeCompleto.indexOf(''{'');\n    if (indiceJson !== -1) {\n      const posibleJson = mensajeCompleto.substring(indiceJson);\n      try {\n        // Reemplazar las barras invertidas escapadas para obtener un JSON válido\n        const jsonLimpio = posibleJson.replace(/\\\\\"/g, ''\"'');\n        const objetoError = JSON.parse(jsonLimpio);\n        // Extraemos el campo \"error\" del JSON (el mensaje para el usuario)\n        if (objetoError.error) {\n          mensajeExtraido = objetoError.error;\n        }\n      } catch (e) {\n        // Si falla el parseo, podemos dejar el mensaje original o null\n        console.error(''Error al parsear JSON:'', e);\n      }\n    }\n  }\n\n  // Agregamos el campo extraído al item (si se encontró)\n  item.json.error_extraido = mensajeExtraido || ''No se pudo extraer el error'';\n}\n\n// Devolvemos todos los elementos modificados\nreturn $input.all();"},"type":"n8n-nodes-base.code","typeVersion":2,"position":[-1632,-192],"id":"60003be4-db10-4a73-92ae-b96a6e9c264d","name":"extraer_error"},{"parameters":{"conditions":{"options":{"caseSensitive":true,"leftValue":"","typeValidation":"strict","version":3},"conditions":[{"id":"37919165-cf06-468c-8339-5cb3cfe30d54","leftValue":"={{ $json.paso_actual }}","rightValue":"COMPLETADO","operator":{"type":"string","operation":"equals"}}],"combinator":"and"},"options":{}},"type":"n8n-nodes-base.if","typeVersion":2.3,"position":[-1072,-512],"id":"ae0e54a7-c928-4b80-9f85-4f85433dafd9","name":"If"},{"parameters":{"method":"POST","url":"https://integraiadev.integraia.lat/chat_bot_integra/capturar_lead_http","sendHeaders":true,"headerParameters":{"parameters":[{"name":"Content-Type","value":"application/json"}]},"sendBody":true,"bodyParameters":{"parameters":[{"name":"solicitar_vat","value":"={{$json.datos_paciente?.solicitar_vat || '''' }}"},{"name":"solicitar_phone","value":"={{ $json.datos_paciente?.solicitar_phone || '''' }}"},{"name":"solicitar_name","value":"={{ $json.datos_paciente?.solicitar_name || '''' }}"},{"name":"solicitar_birthdate","value":"={{  $json.datos_paciente?.solicitar_birthdate || '''' }}"},{"name":"plataforma","value":"={{ $json.tool_input?.plataforma || $json.platform || ''whatsapp'' }}"},{"name":"solicitar_fecha_preferida","value":"={{  $json.datos_paciente?.solicitar_fecha_preferida || '''' }}"},{"name":"solicitar_hora_preferida","value":"={{  $json.datos_paciente?.solicitar_hora_preferida || '''' }}"},{"name":"solicitar_servicio","value":"={{ $json.datos_paciente?.solicitar_servicio || '''' }}"},{"name":"solicitar_medio_pago","value":"={{ $json.datos_paciente?.solicitar_medio_pago || '''' }}"},{"name":"solicitar_es_paciente_nuevo","value":"={{$json.datos_paciente?.solicitar_es_paciente_nuevo || '''' }}"},{"name":"solicitar_membresia_interes","value":"={{ $json.datos_paciente?.solicitar_membresia_interes || '''' }}"},{"name":"solicitar_foto_vat","value":"={{  $json.datos_paciente?.solicitar_foto_vat |